globalThis.__BQ = {"transkripsiyon":{"ilkokul":{"kolay":[{"q":"Vücudumuzdaki bilgiler DNA'da saklanır. Bu bilgilerin bir kopyasının çıkarılması gerekir. DNA'daki bilgiyi kopyalayan haberci molekül hangisidir?","steps":[{"t":"DNA bir defter gibidir","a":"Bilgiler DNA'da yazılıdır","d":"Hücrenin içinde DNA bulunur ve burada vücudumuzla ilgili bütün bilgiler yazılıdır. DNA çok değerli olduğu için çekirdeğin içinde korunur. Bu yüzden DNA dışarı çıkmaz."},{"t":"Bilginin kopyası çıkarılır","a":"mRNA kopyayı taşır","d":"DNA'daki bilgi, mRNA adı verilen bir molekül tarafından kopyalanır. Bu kopya, defterdeki yazıyı bir kâğıda geçirmeye benzer. Böylece bilgi çekirdek dışına taşınabilir."}],"ans":"mRNA (haberci RNA)"},{"q":"Transkripsiyon olayı sırasında DNA'daki bilgi kopyalanır. Bu kopyalama işlemi hücrenin hangi bölümünde yapılır?","steps":[{"t":"DNA nerede bulunur?","a":"Çekirdekte bulunur","d":"Hücrenin yöneticisi olan çekirdek, DNA'yı içinde saklar. DNA çok önemli olduğu için bu güvenli yerde durur. Kopyalama da DNA'nın olduğu yerde başlar."},{"t":"Kopyalama yeri","a":"Çekirdekte gerçekleşir","d":"DNA'dan mRNA kopyası çıkarmak için işlem çekirdeğin içinde yapılır. Burada bilgi mRNA'ya aktarılır. Sonra mRNA çekirdekten dışarı çıkar."}],"ans":"Çekirdekte"},{"q":"Bir öğrenci tahtadaki yazıyı defterine geçiriyor. Hücrede DNA'daki bilginin mRNA'ya geçirilmesi de buna benzer. Bu olaya ne ad verilir?","steps":[{"t":"Yazı kopyalanıyor","a":"Bilgi aktarılır","d":"Öğrenci tahtadaki yazıyı silmeden defterine geçirir. Aynı şekilde DNA'daki bilgi de silinmeden mRNA'ya aktarılır. DNA olduğu gibi kalır."},{"t":"Olayın adı","a":"Transkripsiyon denir","d":"DNA'daki bilginin mRNA'ya kopyalanmasına transkripsiyon denir. Bu kelime kopyalama anlamına gelir. Hücrede protein yapmak için ilk adımdır."}],"ans":"Transkripsiyon (yazılım)"},{"q":"Transkripsiyon sırasında DNA'nın iki ipliğinden sadece biri kopya için kullanılır. Kopya çıkarmak için örnek alınan ipliğe ne ad verilir?","steps":[{"t":"DNA iki iplikten oluşur","a":"İki sarmal vardır","d":"DNA merdivene benzer ve iki ipliği vardır. Kopya çıkarılırken bu iki iplikten yalnızca biri kullanılır. Diğer iplik kopyaya katılmaz."},{"t":"Örnek alınan iplik","a":"Kalıp iplik kullanılır","d":"Kopya çıkarmak için örnek alınan ipliğe kalıp iplik denir. Kalıp, üzerine bakarak kopya yaptığımız parça demektir. mRNA bu kalıba bakılarak yapılır."}],"ans":"Kalıp iplik"},{"q":"mRNA, DNA'dan kopyalandıktan sonra bir yere gitmesi gerekir. Protein üretiminde kullanılmak üzere mRNA çekirdekten nereye doğru hareket eder?","steps":[{"t":"mRNA hazır olur","a":"Kopya tamamlanır","d":"Çekirdekte DNA'dan mRNA kopyası çıkarılır. Bu kopya, vücudun ihtiyaç duyduğu bilgiyi taşır. mRNA artık görevini yapmaya hazırdır."},{"t":"mRNA dışarı çıkar","a":"Sitoplazmaya gider","d":"mRNA çekirdekten çıkıp hücrenin sıvı kısmı olan sitoplazmaya geçer. Burada protein üretimi yapılır. mRNA bilgiyi bu alana taşır."}],"ans":"Sitoplazmaya (hücre sıvısına)"}],"zor":[{"q":"DNA'da harfler A, T, G, C şeklindedir ama mRNA'da T harfi bulunmaz. mRNA kopyalanırken DNA'daki T harfinin yerine hangi yeni harf gelir?","steps":[{"t":"DNA'nın harfleri","a":"A, T, G, C vardır","d":"DNA dört çeşit harften oluşur ve bunlar A, T, G, C'dir. Bu harfler bilgiyi oluşturur. mRNA yapılırken bu harflere bakılır."},{"t":"mRNA'da fark vardır","a":"T harfi yoktur","d":"mRNA'da timin yani T harfi bulunmaz. Onun yerine yeni bir harf kullanılır. Bu, mRNA'yı DNA'dan ayıran önemli bir özelliktir."},{"t":"T yerine gelen harf","a":"Urasil (U) gelir","d":"mRNA'da T harfinin yerine urasil yani U harfi gelir. Yani DNA'da T olan yerde mRNA'da U bulunur. Bu kural transkripsiyonda her zaman geçerlidir."}],"ans":"Urasil (U)"},{"q":"Bir hücrede transkripsiyon işini yapan özel bir enzim vardır. DNA'dan mRNA üreten bu yardımcı enzimin adı nedir?","steps":[{"t":"Kopyalamaya yardımcı gerekir","a":"Bir enzim çalışır","d":"mRNA kendi kendine yapılamaz. Bu işi yapan özel bir yardımcı molekül vardır. Bu yardımcıya enzim denir."},{"t":"Enzimin görevi","a":"mRNA üretir","d":"Bu enzim DNA'yı okur ve ona uygun mRNA üretir. Yani kopyalama işini bu enzim yapar. İşlem boyunca DNA'nın üzerinde ilerler."},{"t":"Enzimin adı","a":"RNA polimeraz","d":"mRNA üreten enzimin adı RNA polimerazdır. Bu enzim olmadan transkripsiyon başlayamaz. RNA harflerini birbirine ekleyerek mRNA yapar."}],"ans":"RNA polimeraz enzimi"},{"q":"DNA'da bir bölgenin harfleri sırayla A, G, C, T şeklindedir. Bu bölgeden mRNA kopyalanırsa, A harfinin karşısına mRNA'da hangi harf gelir?","steps":[{"t":"Eşleşme kuralı","a":"Harfler eşleşir","d":"mRNA yapılırken DNA harfleri belli bir kurala göre eşleşir. Her harfin karşısına belirli bir harf gelir. Bu kural değişmez."},{"t":"A harfinin karşılığı","a":"mRNA'da U gelir","d":"DNA'daki A harfinin karşısına mRNA'da U yani urasil gelir. Çünkü mRNA'da T harfi yoktur, onun yerine U vardır. Böylece A ile U eşleşir."}],"ans":"U (urasil)"},{"q":"Transkripsiyon bittikten sonra DNA'nın durumu merak ediliyor. Kopyalama işlemi bittiğinde DNA bozulur mu yoksa eski hâline mi döner?","steps":[{"t":"Kopyalama sırasında","a":"DNA açılır","d":"mRNA yapmak için DNA'nın iki ipliği geçici olarak açılır. Bu açılma sadece kopyalama yapılan bölgede olur. Kopya bittikten sonra durum değişir."},{"t":"İşlem bitince","a":"DNA tekrar kapanır","d":"Kopyalama bittiğinde DNA'nın iki ipliği yeniden birleşir. DNA bozulmaz, eski hâline döner. Böylece DNA tekrar tekrar kullanılabilir."}],"ans":"DNA eski hâline döner (bozulmaz)"},{"q":"Bir öğretmen DNA'yı kütüphanedeki bir kitaba benzetiyor. Kitap kütüphaneden çıkmaz ama fotokopisi çıkarılıp dışarı götürülür. Bu örnekte fotokopi neye karşılık gelir?","steps":[{"t":"Kitap çıkmaz","a":"DNA çekirdekte kalır","d":"Kütüphanedeki değerli kitap dışarı çıkarılmaz, sadece içeride kullanılır. DNA da aynı şekilde çekirdekten dışarı çıkmaz. Bu yüzden bilgisinin kopyası alınır."},{"t":"Fotokopi alınır","a":"mRNA dışarı çıkar","d":"Kitabın fotokopisi çıkarılıp dışarı götürülebilir. Hücrede de DNA'nın kopyası olan mRNA çekirdekten dışarı çıkar. Yani fotokopi mRNA'ya karşılık gelir."}],"ans":"mRNA (DNA'nın kopyası)"}]},"ortaokul":{"kolay":[{"q":"Transkripsiyon, DNA'daki genetik bilginin mRNA'ya aktarıldığı olaydır. Bu olayda DNA'nın iki ipliğinden hangisi mRNA sentezi için kalıp olarak kullanılır?","steps":[{"t":"DNA çift ipliklidir","a":"İki iplik bulunur","d":"DNA birbirine sarılmış iki iplikten oluşur. Transkripsiyon sırasında bu iplikler birbirinden ayrılır. Ancak her ikisi de kopyalama için kullanılmaz."},{"t":"Kalıp seçimi","a":"Tek iplik kalıptır","d":"mRNA sentezinde DNA'nın yalnızca bir ipliği kalıp olarak kullanılır. Bu ipliğe kalıp iplik veya anlamlı olmayan iplik denir. Diğer iplik kopya işlemine katılmaz."}],"ans":"Kalıp (anlamlı olmayan) iplik"},{"q":"mRNA sentezi sırasında RNA nükleotitlerini birbirine bağlayan ve DNA'yı okuyan enzim vardır. Transkripsiyonu gerçekleştiren bu enzimin adı nedir?","steps":[{"t":"Enzim gereklidir","a":"Bir enzim katalizler","d":"Transkripsiyon kendiliğinden olmaz, bir enzim tarafından yürütülür. Bu enzim DNA kalıbını okur. Okuduğu bilgiye göre RNA nükleotitlerini sıralar."},{"t":"Enzimin görevi","a":"RNA polimeraz bağlar","d":"RNA polimeraz enzimi RNA nükleotitlerini birbirine peptit değil fosfodiester bağıyla ekler ve mRNA zincirini uzatır. Kalıp iplik boyunca ilerleyerek mRNA'yı tamamlar."}],"ans":"RNA polimeraz enzimi"},{"q":"mRNA molekülü DNA'ya çok benzer ama bazı farkları vardır. RNA'da timin bazı yerine bulunan azotlu organik baz hangisidir?","steps":[{"t":"DNA ve RNA bazları","a":"Bazlar kısmen farklıdır","d":"DNA'da adenin, timin, guanin ve sitozin bazları bulunur. RNA'da ise bu bazlardan biri yer almaz. Onun yerine başka bir baz kullanılır."},{"t":"Timin yerine gelen baz","a":"Urasil yer alır","d":"RNA'da timin yerine urasil bazı bulunur. Yani transkripsiyonda DNA'daki adenin karşısına RNA'da urasil eklenir. Bu, RNA'yı DNA'dan ayıran temel özelliktir."}],"ans":"Urasil"},{"q":"Ökaryot bir hücrede transkripsiyon belirli bir organelde gerçekleşir. DNA'nın bulunduğu ve mRNA'nın sentezlendiği bu organel hangisidir?","steps":[{"t":"DNA'nın yeri","a":"Çekirdekte korunur","d":"Ökaryot hücrelerde DNA çekirdek zarıyla çevrili çekirdekte bulunur. Genetik bilgi burada korunur. Transkripsiyon bu bilginin yanında başlar."},{"t":"Sentez yeri","a":"Çekirdekte yapılır","d":"Transkripsiyon, DNA'nın bulunduğu çekirdekte gerçekleşir. Burada üretilen mRNA daha sonra çekirdek dışına çıkar. Sitoplazmada protein sentezinde kullanılır."}],"ans":"Çekirdek"},{"q":"Transkripsiyon ile translasyon birbirini izleyen iki olaydır. Transkripsiyon sonucunda oluşan ve translasyonda kalıp olarak kullanılan molekül hangisidir?","steps":[{"t":"Transkripsiyonun ürünü","a":"mRNA oluşur","d":"Transkripsiyon sonucunda DNA'daki bilgi mRNA'ya aktarılır. Böylece bir mRNA molekülü meydana gelir. Bu molekül genetik bilgiyi taşır."},{"t":"Sonraki adımda görev","a":"mRNA kalıp olur","d":"Oluşan mRNA, translasyon olayında protein sentezi için kalıp görevi görür. Ribozomda mRNA'daki bilgi okunur. Böylece protein üretimi yapılır."}],"ans":"mRNA"}],"zor":[{"q":"DNA kalıp ipliğinin bir bölümü 3'-T A C G G T-5' şeklindedir. Bu kalıptan sentezlenen mRNA'nın baz dizisi nasıl olur?","steps":[{"t":"Eşleşme kuralları","a":"A-U, T-A, G-C, C-G","d":"Transkripsiyonda kalıp ipliğindeki her baz karşısına RNA bazı eklenir. DNA'daki A karşısına U, T karşısına A, G karşısına C, C karşısına G gelir. RNA'da timin yoktur, urasil kullanılır."},{"t":"Karşılıkları bulma","a":"A U G C C A oluşur","d":"Kalıptaki T-A-C-G-G-T baz sırası için karşılıklar bulunur. T karşısına A, A karşısına U, C karşısına G, G karşısına C, G karşısına C, T karşısına A gelir. Böylece mRNA dizisi belirlenir."},{"t":"mRNA yazımı","a":"5'-A U G C C A-3'","d":"mRNA, kalıba ters yönde ve karşıt olarak sentezlenir. Elde edilen mRNA dizisi 5' ucundan başlayarak A U G C C A şeklindedir. Bu dizi DNA'daki bilginin kopyasıdır."}],"ans":"5'-A U G C C A-3'"},{"q":"Bir DNA bölgesinde kalıp olmayan (anlamlı) iplik 5'-A T G C-3' şeklindedir. Bu bölgeden sentezlenen mRNA'nın dizisi ne olur?","steps":[{"t":"Anlamlı iplik ile mRNA","a":"Diziler neredeyse aynıdır","d":"Anlamlı iplik, mRNA ile aynı baz dizisine sahiptir çünkü kalıp ipliğin tamamlayıcısıdır. Tek fark, mRNA'da timin yerine urasil bulunmasıdır. Bu yüzden T'leri U yaparak mRNA bulunur."},{"t":"Dönüşüm yapılır","a":"T yerine U yazılır","d":"Anlamlı iplikteki A-T-G-C dizisinde timin urasil ile değiştirilir. A aynı kalır, T urasile dönüşür, G ve C aynı kalır. Böylece mRNA dizisi elde edilir."},{"t":"mRNA sonucu","a":"5'-A U G C-3'","d":"Elde edilen mRNA dizisi 5'-A U G C-3' şeklindedir. Yani anlamlı iplik ile mRNA aynı yöndedir. Sadece timin bazı urasil ile yer değiştirmiştir."}],"ans":"5'-A U G C-3'"},{"q":"Transkripsiyon ile DNA replikasyonu farklı amaçlara hizmet eder. Bu iki olay arasında üretilen molekül ve kullanılan enzim açısından temel fark nedir?","steps":[{"t":"Replikasyonun amacı","a":"DNA çoğaltılır","d":"DNA replikasyonunda DNA'nın tamamı eşlenerek iki özdeş DNA oluşturulur. Bu işlemde DNA polimeraz enzimi görev yapar. Ürün yeni bir DNA molekülüdür."},{"t":"Transkripsiyonun amacı","a":"mRNA üretilir","d":"Transkripsiyonda DNA'nın yalnızca bir bölümü kopyalanarak mRNA üretilir. Bu işlemde RNA polimeraz enzimi görev yapar. Ürün bir RNA molekülüdür."},{"t":"Temel fark","a":"Enzim ve ürün farklı","d":"Replikasyonda DNA polimeraz ile DNA, transkripsiyonda RNA polimeraz ile mRNA üretilir. Replikasyon tüm DNA'yı, transkripsiyon belirli genleri kopyalar. Böylece amaçları farklılaşır."}],"ans":"Replikasyonda DNA polimeraz ile DNA, transkripsiyonda RNA polimeraz ile mRNA üretilir"},{"q":"Bir mRNA molekülünde 80 adet urasil bazı bulunmaktadır. Buna göre bu mRNA'nın kalıp DNA ipliğinde en az kaç adenin bazı bulunmalıdır?","steps":[{"t":"U bazının kaynağı","a":"A karşısına U gelir","d":"Transkripsiyonda kalıp DNA ipliğindeki her adenin karşısına mRNA'da urasil eklenir. Yani mRNA'daki urasil sayısı, kalıptaki adenin sayısına bağlıdır. Her A bir U üretir."},{"t":"Eşitlik kurulur","a":"U sayısı = A sayısı","d":"mRNA'daki urasil sayısı, kalıp ipliğindeki adenin sayısına eşittir. Bu mRNA'da 80 urasil olduğuna göre kalıpta da 80 adenin vardır. Bu doğrudan bir eşleşmedir."},{"t":"Sonuç","a":"80 adenin","d":"Kalıp DNA ipliğinde en az 80 adenin bazı bulunmalıdır. Çünkü 80 urasilin her biri bir adenin karşısına eklenmiştir. Sayılar birebir eşleşir."}],"ans":"80 adenin"},{"q":"Transkripsiyon sırasında RNA polimeraz enziminin DNA üzerindeki davranışı önemlidir. Bu enzim kalıp iplik boyunca ne yapar ve mRNA nasıl uzar?","steps":[{"t":"Enzim DNA'ya bağlanır","a":"Belirli bölgeden başlar","d":"RNA polimeraz, genin başlangıç bölgesine bağlanarak DNA'nın iki ipliğini birbirinden ayırır. Açılan bölgede kalıp iplik ortaya çıkar. Böylece kopyalama başlayabilir."},{"t":"Enzim ilerler","a":"Nükleotit ekler","d":"RNA polimeraz kalıp iplik boyunca hareket eder ve karşısına uygun RNA nükleotitlerini ekler. Her baz, eşleşme kuralına göre seçilir. mRNA zinciri giderek uzar."},{"t":"Sentez tamamlanır","a":"mRNA tamamlanır","d":"Enzim genin sonuna ulaştığında mRNA sentezi biter ve mRNA serbest kalır. DNA iplikleri yeniden birleşir. Oluşan mRNA çekirdekten çıkmaya hazırdır."}],"ans":"RNA polimeraz kalıp boyunca ilerleyerek uygun RNA nükleotitlerini ekler ve mRNA uzar"}]},"lise":{"kolay":[{"q":"Transkripsiyon, gen anlatımının ilk basamağıdır. Bu olayda DNA'daki kalıtsal bilginin aktarıldığı molekül hangisidir ve işlemin temel amacı nedir?","steps":[{"t":"Gen anlatımı","a":"İki ana basamak","d":"Gen anlatımı, transkripsiyon ve translasyon olarak iki temel basamaktan oluşur. Transkripsiyon bu sürecin ilk adımıdır. Burada DNA'daki bilgi RNA'ya aktarılır."},{"t":"Aktarılan molekül","a":"mRNA sentezlenir","d":"Transkripsiyon sonucunda DNA'daki kalıtsal bilgi haberci RNA'ya yani mRNA'ya kopyalanır. Bu mRNA bilgiyi taşıyan ara moleküldür. Protein bilgisinin habercisidir."},{"t":"Amaç","a":"Bilginin taşınması","d":"Transkripsiyonun amacı, çekirdekteki DNA bilgisini sitoplazmaya taşınabilecek bir RNA'ya dönüştürmektir. Böylece protein sentezi için gerekli kalıp hazırlanır. mRNA bu görevi üstlenir."}],"ans":"mRNA sentezlenir; amaç DNA bilgisini protein sentezi için aktarmaktır"},{"q":"Transkripsiyonda RNA polimeraz enzimi merkezi rol oynar. Bu enzimin transkripsiyon başlangıcında DNA üzerinde yaptığı ilk işlem nedir?","steps":[{"t":"Enzimin tanıması","a":"Promotör bölgeye bağlanır","d":"RNA polimeraz, genin başında bulunan promotör adlı özel bir bölgeyi tanır ve buraya bağlanır. Bu bölge enzime nereden başlayacağını gösterir. Bağlanma transkripsiyonun ilk işlemidir."},{"t":"DNA'nın açılması","a":"İki iplik ayrılır","d":"Enzim bağlandıktan sonra DNA'nın iki ipliğini birbirinden ayırarak açar. Açılan bölgede kalıp iplik kullanıma hazır hâle gelir. Böylece RNA sentezi başlayabilir."}],"ans":"Promotör bölgeye bağlanıp DNA ipliklerini ayırır"},{"q":"mRNA molekülü tek ipliklidir ve DNA'dan bazı yönlerden farklıdır. RNA'nın yapısında bulunan beş karbonlu şeker ile azotlu baz açısından DNA'dan farkları nelerdir?","steps":[{"t":"Şeker farkı","a":"Riboz bulunur","d":"DNA'da deoksiriboz şekeri bulunurken RNA'da riboz şekeri bulunur. Riboz, deoksiribozdan bir oksijen atomu fazlasıyla ayrılır. Bu fark molekülün yapısını etkiler."},{"t":"Baz farkı","a":"Urasil bulunur","d":"DNA'da timin bazı yer alırken RNA'da timin yerine urasil bulunur. Diğer üç baz olan adenin, guanin ve sitozin her ikisinde de ortaktır. Bu nedenle RNA'da timin görülmez."},{"t":"İplik sayısı","a":"Tek ipliklidir","d":"DNA çift iplikli sarmal yapıdayken mRNA tek ipliklidir. Bu yapı mRNA'nın ribozomda kolayca okunmasını sağlar. Böylece RNA daha esnek bir molekül olur."}],"ans":"RNA'da riboz şekeri, timin yerine urasil bulunur ve mRNA tek ipliklidir"},{"q":"Ökaryot ve prokaryot hücrelerde transkripsiyonun yeri farklılık gösterir. Ökaryot hücrelerde transkripsiyon nerede gerçekleşir?","steps":[{"t":"Ökaryot hücre özelliği","a":"Zarlı çekirdek vardır","d":"Ökaryot hücrelerde DNA, çekirdek zarıyla çevrili gerçek bir çekirdekte bulunur. Bu nedenle DNA sitoplazmadan ayrılmıştır. Genetik bilgi burada korunur."},{"t":"Transkripsiyon yeri","a":"Çekirdekte olur","d":"DNA çekirdekte bulunduğu için transkripsiyon da çekirdekte gerçekleşir. Burada üretilen mRNA daha sonra sitoplazmaya geçer. Translasyon ise sitoplazmadaki ribozomlarda olur."}],"ans":"Çekirdekte"},{"q":"Transkripsiyon sırasında baz eşleşmesi belirli kurallarla yapılır. DNA kalıp ipliğindeki guanin bazının karşısına mRNA'da hangi baz eklenir?","steps":[{"t":"Baz eşleşme kuralı","a":"G ile C eşleşir","d":"Transkripsiyonda DNA'daki guanin her zaman karşısına sitozin gelecek şekilde eşleşir. Bu eşleşme hem DNA'da hem de RNA sentezinde geçerlidir. Guanin ve sitozin birbirini tamamlar."},{"t":"mRNA'da karşılık","a":"Sitozin eklenir","d":"DNA kalıbındaki guanin bazının karşısına mRNA'da sitozin bazı eklenir. Sitozin DNA ve RNA'da ortak bulunan bir bazdır. Bu nedenle değişmeden eklenir."}],"ans":"Sitozin (C)"},{"q":"Bir genin transkripsiyonu sonucunda farklı RNA çeşitleri üretilebilir. Protein sentezinde kalıp görevi gören ve kodonları taşıyan RNA çeşidi hangisidir?","steps":[{"t":"RNA çeşitleri","a":"Üç temel RNA","d":"Hücrede mRNA, tRNA ve rRNA olmak üzere üç temel RNA çeşidi bulunur. Bunların hepsi transkripsiyonla DNA'dan üretilir. Her birinin görevi farklıdır."},{"t":"Kalıp görevli RNA","a":"mRNA seçilir","d":"Protein sentezinde kalıp görevi gören RNA, haberci RNA yani mRNA'dır. mRNA üzerinde kodon adı verilen üçlü baz dizileri bulunur. Bu kodonlar protein bilgisini taşır."}],"ans":"mRNA (haberci RNA)"},{"q":"Transkripsiyon tamamlandığında DNA ve mRNA'nın akıbeti farklıdır. İşlem bittikten sonra DNA'ya ve oluşan mRNA'ya ne olur?","steps":[{"t":"DNA'nın durumu","a":"Yeniden kapanır","d":"Transkripsiyon sırasında geçici olarak açılan DNA iplikleri, işlem bittikten sonra yeniden birleşir. DNA bozulmaz ve tekrar kullanılabilir hâle gelir. Genetik bilgi korunur."},{"t":"mRNA'nın yolculuğu","a":"Çekirdekten çıkar","d":"Oluşan mRNA, kalıptan ayrılarak serbest kalır ve çekirdekten sitoplazmaya geçer. Burada ribozomlarda protein sentezinde kullanılır. mRNA görevini sitoplazmada yapar."}],"ans":"DNA yeniden kapanır; mRNA çekirdekten sitoplazmaya geçer"},{"q":"Transkripsiyonda kullanılan kalıp iplik ile kullanılmayan iplik farklı isimlerle anılır. mRNA ile aynı baz dizisine sahip olan (timin yerine urasil hariç) iplik hangisidir?","steps":[{"t":"İki iplik isimleri","a":"Kalıp ve anlamlı","d":"DNA'nın transkripsiyonda kullanılan ipliğine kalıp iplik, kullanılmayan ipliğine anlamlı iplik denir. Kalıp iplik mRNA'nın tamamlayıcısıdır. Anlamlı iplik ise farklı bir ilişki gösterir."},{"t":"mRNA ile benzerlik","a":"Anlamlı iplik benzer","d":"mRNA, kalıp ipliğin tamamlayıcısı olduğu için anlamlı iplikle aynı baz dizisine sahiptir. Tek fark, mRNA'da timin yerine urasil bulunmasıdır. Bu nedenle anlamlı iplik mRNA ile eşdeğer dizilidir."}],"ans":"Anlamlı (kalıp olmayan) iplik"},{"q":"Transkripsiyonda mRNA sentezi belirli bir yönde ilerler. RNA polimeraz enzimi mRNA zincirini hangi yönde uzatır?","steps":[{"t":"Sentez yönü kavramı","a":"Belirli bir yön vardır","d":"Nükleik asit sentezinde zincirler belirli bir yönde uzar. Bu yön, nükleotitlerin nasıl eklendiğini belirler. RNA sentezi de bu kurala uyar."},{"t":"mRNA uzama yönü","a":"5' ucundan 3' ucuna","d":"RNA polimeraz, mRNA zincirini 5' ucundan 3' ucuna doğru uzatır. Yeni nükleotitler her zaman 3' ucuna eklenir. Bu nedenle kalıp iplik 3'-5' yönünde okunur."}],"ans":"5' ucundan 3' ucuna doğru"},{"q":"mRNA üzerindeki bilgiler üçlü gruplar hâlinde okunur. mRNA'da bir aminoasidi belirleyen üç bazlık birime ne ad verilir?","steps":[{"t":"mRNA'nın okunması","a":"Üçlü gruplar","d":"mRNA üzerindeki bazlar protein sentezinde üçer üçer gruplanarak okunur. Her grup belirli bir bilgi taşır. Bu sayede genetik şifre çözülür."},{"t":"Üçlü birimin adı","a":"Kodon denir","d":"mRNA'da bir aminoasidi belirleyen üç bazlık birime kodon denir. Her kodon genellikle bir aminoaside karşılık gelir. Kodonlar protein sentezinin temel şifresidir."}],"ans":"Kodon"},{"q":"Transkripsiyon ve replikasyon farklı miktarlarda DNA kullanır. Bir hücrede transkripsiyon, DNA'nın tamamını mı yoksa belirli bir bölümünü mü kalıp olarak kullanır?","steps":[{"t":"Replikasyon ile karşılaştırma","a":"Replikasyon tümünü kopyalar","d":"DNA replikasyonunda hücre bölünmeden önce DNA'nın tamamı eşlenir. Çünkü her yeni hücreye eksiksiz genetik bilgi gerekir. Bu nedenle tüm DNA kopyalanır."},{"t":"Transkripsiyon kapsamı","a":"Belirli gen kopyalanır","d":"Transkripsiyonda ise yalnızca ihtiyaç duyulan gen veya genler kopyalanır. Yani DNA'nın belirli bir bölümü kalıp olarak kullanılır. İhtiyaca göre farklı genler okunur."}],"ans":"Yalnızca belirli bir bölümünü (geni)"},{"q":"Transkripsiyonun ürünü olan mRNA protein bilgisini taşır. Bir genin transkripsiyonuyla doğrudan oluşan ve translasyona katılan ana RNA molekülü hangisidir?","steps":[{"t":"Transkripsiyon ürünü","a":"RNA üretilir","d":"Transkripsiyon sonucunda DNA'dan RNA molekülleri üretilir. Bu RNA çeşitleri içinde protein bilgisini taşıyan özel bir tür vardır. Bu tür translasyonda doğrudan kullanılır."},{"t":"Translasyona katılan","a":"mRNA görev alır","d":"Protein bilgisini taşıyan ve translasyonda kalıp görevi gören molekül mRNA'dır. mRNA, ribozomda okunarak protein üretimine yön verir. Bu nedenle translasyonun ana molekülüdür."}],"ans":"mRNA"},{"q":"Transkripsiyonda enzim DNA'yı geçici olarak çözer. RNA polimerazın kalıp iplik boyunca ilerlerken DNA üzerinde oluşturduğu açık bölgeye ne olur?","steps":[{"t":"Açık bölge oluşumu","a":"İplikler ayrılır","d":"RNA polimeraz ilerlerken DNA'nın iki ipliğini bölgesel olarak birbirinden ayırır. Bu açık bölgede kalıp iplik okunur. Açıklık sadece enzimin bulunduğu yerde oluşur."},{"t":"Enzim geçtikten sonra","a":"İplikler yeniden kapanır","d":"RNA polimeraz bir bölgeyi okuyup ileri gittikçe, arkada kalan DNA iplikleri yeniden birleşir. Böylece DNA sürekli açık kalmaz. Sadece okunan kısa bölge geçici olarak açıktır."}],"ans":"Enzim geçtikten sonra DNA iplikleri yeniden kapanır"},{"q":"Transkripsiyon sırasında serbest nükleotitler kullanılır. mRNA sentezi için ortamda hangi tür serbest yapı taşları bulunmalıdır?","steps":[{"t":"Yapı taşı ihtiyacı","a":"Nükleotit gerekir","d":"mRNA bir nükleik asittir ve yapı taşları nükleotitlerdir. Sentez için ortamda yeterli sayıda serbest nükleotit bulunması gerekir. Bu nükleotitler zincire eklenir."},{"t":"RNA nükleotitleri","a":"A, U, G, C içerir","d":"mRNA sentezinde RNA tipi nükleotitler kullanılır ve bunlar adenin, urasil, guanin, sitozin içerir. Timinli nükleotit RNA'da kullanılmaz. Riboz şekeri içeren nükleotitler gereklidir."}],"ans":"Adenin, urasil, guanin ve sitozin içeren RNA (ribonükleotit) yapı taşları"},{"q":"Transkripsiyon ile bir genin yalnızca bir ipliği okunur. Aynı genin DNA'sında bir iplik kalıp seçilirken neden diğer iplik kalıp olarak kullanılmaz?","steps":[{"t":"İki iplik farklı bilgi taşır","a":"Diziler tamamlayıcıdır","d":"DNA'nın iki ipliği birbirinin tamamlayıcısıdır ve farklı baz dizilerine sahiptir. Eğer her iki iplik de kalıp olarak kullanılsaydı, iki farklı ve uyumsuz mRNA oluşurdu. Bu durum hatalı proteinlere yol açardı."},{"t":"Doğru protein için seçim","a":"Tek kalıp kullanılır","d":"Doğru protein bilgisini taşıyan mRNA'nın oluşması için yalnızca anlamlı bilgiyi veren kalıp iplik okunur. Böylece her gen için tutarlı ve doğru mRNA üretilir. Hücre bu seçimi promotör yönüyle belirler."}],"ans":"Doğru ve tutarlı mRNA oluşması için yalnızca anlamlı bilgi veren kalıp iplik okunur"}],"zor":[{"q":"Bir genin kalıp ipliği 3'-T A C G A T C-5' dizisindedir. Bu kalıptan sentezlenen mRNA'nın baz dizisini ve yönünü belirleyiniz.","steps":[{"t":"Eşleşme kurallarını uygula","a":"A-U, T-A, G-C, C-G","d":"Transkripsiyonda kalıp ipliğindeki her baz, tamamlayıcı RNA bazıyla eşleşir. DNA'daki T karşısına A, A karşısına U, G karşısına C, C karşısına G gelir. RNA'da timin bulunmadığından adenin karşısına urasil eklenir."},{"t":"Bazları sırayla bul","a":"A U G C U A G","d":"Kalıptaki T-A-C-G-A-T-C dizisi için karşılıklar bulunur. T'ye A, A'ya U, C'ye G, G'ye C, A'ya U, T'ye A, C'ye G eklenir. Böylece mRNA bazları belirlenir."},{"t":"Yönü belirle","a":"Kalıba antiparalel","d":"mRNA, kalıp ipliğe antiparalel yani ters yönde sentezlenir. Kalıp 3'-5' yönünde okunduğundan mRNA 5'-3' yönünde yazılır. Sonuç 5'-A U G C U A G-3' olur."}],"ans":"5'-A U G C U A G-3'"},{"q":"Bir mRNA molekülünün baz dizisi 5'-G C A U U G C-3' şeklindedir. Bu mRNA'yı sentezleyen DNA kalıp ipliğinin baz dizisini ve yönünü bulunuz.","steps":[{"t":"Ters eşleşme yap","a":"mRNA'dan kalıba gidilir","d":"mRNA, kalıp ipliğin tamamlayıcısı olduğundan kalıbı bulmak için ters eşleşme yapılır. mRNA'daki G karşısına C, C karşısına G, A karşısına T, U karşısına A gelir. RNA'daki urasil, DNA'da adenin karşılığıdır."},{"t":"Bazları çevir","a":"C G T A A C G","d":"mRNA'daki G-C-A-U-U-G-C dizisi için kalıp bazları bulunur. G'ye C, C'ye G, A'ya T, U'ya A, U'ya A, G'ye C, C'ye G eklenir. Böylece kalıp baz dizisi elde edilir."},{"t":"Yönü ayarla","a":"Antiparalel yazılır","d":"Kalıp iplik mRNA'ya antiparaleldir, bu yüzden ters yönde yazılır. mRNA 5'-3' ise kalıp 3'-5' yönündedir. Sonuç 3'-C G T A A C G-5' olur."}],"ans":"3'-C G T A A C G-5'"},{"q":"Bir mRNA molekülünde 120 adenin, 90 urasil, 60 guanin ve 30 sitozin bazı bulunmaktadır. Bu mRNA'yı sentezleyen DNA kalıp ipliğindeki timin ve adenin sayılarını bulunuz.","steps":[{"t":"mRNA-kalıp ilişkisi","a":"Tamamlayıcı eşleşme","d":"mRNA, kalıp ipliğin tamamlayıcısıdır, dolayısıyla mRNA bazları kalıp bazlarıyla eşleşir. mRNA'daki A kalıptaki T ile, mRNA'daki U kalıptaki A ile eşleşir. Bu ilişki sayıların belirlenmesini sağlar."},{"t":"Kalıptaki T sayısı","a":"mRNA'daki A kadar","d":"mRNA'daki adenin, kalıptaki timin karşısına eklenir. mRNA'da 120 adenin olduğuna göre kalıpta 120 timin bulunur. Sayılar birebir eşittir."},{"t":"Kalıptaki A sayısı","a":"mRNA'daki U kadar","d":"mRNA'daki urasil, kalıptaki adenin karşısına eklenir. mRNA'da 90 urasil olduğuna göre kalıpta 90 adenin bulunur. Böylece kalıptaki timin 120, adenin 90 olur."}],"ans":"Kalıpta 120 timin ve 90 adenin bulunur"},{"q":"Bir DNA molekülünün toplam baz sayısı 3000 olup adenin oranı yüzde 30'dur. Bu DNA'nın tek bir ipliği tamamen transkribe edilirse, oluşan mRNA en az kaç nükleotit içerir?","steps":[{"t":"DNA iplik başına baz","a":"1500 nükleotit","d":"DNA çift iplikli olduğundan toplam 3000 baz, her iplikte 1500 nükleotit anlamına gelir. mRNA tek bir iplik kalıbından üretilir. Bu nedenle iplik başına baz sayısı önemlidir."},{"t":"mRNA uzunluğu","a":"Kalıp kadar nükleotit","d":"Transkripsiyonda her kalıp nükleotidi karşısına bir RNA nükleotidi eklenir. Kalıp iplik 1500 nükleotit içerdiğinden mRNA da 1500 nükleotit içerir. Uzunluklar birebir eşleşir."},{"t":"Sonuç","a":"1500 nükleotit","d":"Tek bir DNA ipliği tam transkribe edilirse oluşan mRNA 1500 nükleotit içerir. Adenin oranı uzunluğu değiştirmez, yalnızca baz dağılımını verir. Bu nedenle nükleotit sayısı 1500'dür."}],"ans":"1500 nükleotit"},{"q":"Bir mRNA dizisi 5'-A U G A A A C C C-3' şeklindedir. Bu mRNA'nın sentezlendiği genin anlamlı (kalıp olmayan) ipliğinin baz dizisini ve yönünü bulunuz.","steps":[{"t":"mRNA-anlamlı iplik ilişkisi","a":"Diziler özdeştir","d":"Anlamlı iplik, mRNA ile aynı baz dizisine sahiptir çünkü her ikisi de kalıp ipliğin tamamlayıcısıdır. Tek fark, anlamlı iplikte urasil yerine timin bulunmasıdır. Bu yüzden U bazları T'ye çevrilir."},{"t":"Urasilleri timine çevir","a":"A T G A A A C C C","d":"mRNA'daki A U G A A A C C C dizisinde urasil bazı timine dönüştürülür. A aynı kalır, U timine döner, diğer bazlar değişmez. Böylece anlamlı iplik dizisi elde edilir."},{"t":"Yönü koru","a":"5'-A T G A A A C C C-3'","d":"Anlamlı iplik mRNA ile aynı yönde olduğundan 5'-3' yönü korunur. Sonuç 5'-A T G A A A C C C-3' şeklindedir. Yalnızca timin urasil yerini almıştır."}],"ans":"5'-A T G A A A C C C-3'"},{"q":"Transkripsiyon ve DNA replikasyonu çok benzese de önemli farkları vardır. Kullanılan enzim, ürün, kapsam ve baz açısından bu iki olayı karşılaştırınız.","steps":[{"t":"Enzim farkı","a":"RNA pol. - DNA pol.","d":"Transkripsiyonda RNA polimeraz, replikasyonda DNA polimeraz enzimi görev yapar. RNA polimeraz primer gerektirmezken DNA polimeraz primere ihtiyaç duyar. Bu enzim farkı işlemleri ayırır."},{"t":"Ürün ve kapsam farkı","a":"mRNA - DNA; gen - tüm DNA","d":"Transkripsiyonun ürünü mRNA, replikasyonun ürünü yeni DNA ipliğidir. Transkripsiyon belirli bir geni kopyalarken replikasyon tüm DNA'yı eşler. Böylece kapsamları farklılaşır."},{"t":"Baz farkı","a":"Urasil - timin","d":"Transkripsiyonda timin yerine urasil kullanılır, replikasyonda ise timin korunur. RNA'da riboz, DNA'da deoksiriboz şekeri bulunur. Bu farklar ürünlerin yapısını belirler."}],"ans":"Transkripsiyon: RNA polimeraz, mRNA, gen, urasil; replikasyon: DNA polimeraz, DNA, tüm DNA, timin"},{"q":"Bir gende anlamlı ipliğin bir bölümü 5'-T A C G G A T T-3' dizisindedir. Bu genden sentezlenen mRNA'daki guanin sayısını bulunuz.","steps":[{"t":"Anlamlı iplikten mRNA","a":"T yerine U yazılır","d":"Anlamlı iplik mRNA ile aynı diziye sahiptir, sadece timin urasile dönüşür. Bu nedenle anlamlı iplikteki bazlardan timinleri urasile çevirerek mRNA bulunur. Guanin ve sitozin değişmez."},{"t":"mRNA dizisini bul","a":"U A C G G A U U","d":"Anlamlı iplikteki T A C G G A T T dizisinde timinler urasile çevrilir. Sonuç U A C G G A U U olur. Bu mRNA'nın baz dizisidir."},{"t":"Guanin sayısı","a":"2 guanin","d":"Elde edilen mRNA dizisinde guanin bazları sayılır. U A C G G A U U dizisinde iki adet guanin bulunmaktadır. Bu nedenle mRNA'daki guanin sayısı 2'dir."}],"ans":"2 guanin"},{"q":"Bir mRNA molekülünde toplam 600 nükleotit bulunmaktadır ve bunların yüzde 25'i adenindir. Bu mRNA'yı sentezleyen DNA kalıp ipliğindeki timin sayısını bulunuz.","steps":[{"t":"mRNA'daki adenin sayısı","a":"150 adenin","d":"mRNA'da toplam 600 nükleotit vardır ve bunların yüzde 25'i adenindir. Yüzde 25'in 600 üzerinden karşılığı 150 nükleotittir. Yani mRNA'da 150 adenin bulunur."},{"t":"Adenin-timin ilişkisi","a":"A karşısı kalıpta T","d":"mRNA'daki adenin, kalıp ipliğindeki timin karşısına eklenmiştir. Çünkü transkripsiyonda mRNA'nın adenini, kalıbın timini ile eşleşir. Bu ilişki sayıları eşitler."},{"t":"Kalıptaki timin sayısı","a":"150 timin","d":"mRNA'da 150 adenin bulunduğuna göre kalıpta da 150 timin vardır. Çünkü her adenin bir timin karşısına eklenmiştir. Sonuç olarak kalıp iplikte 150 timin bulunur."}],"ans":"150 timin"},{"q":"Bir hücrede transkripsiyon hızlanırsa, üretilen mRNA sayısının artmasının protein sentezi üzerindeki olası etkisi nedir? Mantıksal olarak açıklayınız.","steps":[{"t":"mRNA artışı","a":"Daha çok kalıp","d":"Transkripsiyon hızlanırsa belirli bir gen için üretilen mRNA sayısı artar. Her mRNA protein sentezi için bir kalıptır. Bu nedenle daha fazla kalıp ortaya çıkar."},{"t":"Ribozom kullanımı","a":"Daha çok translasyon","d":"Artan mRNA sayısı, ribozomların aynı anda daha fazla mRNA okumasına olanak tanır. Her mRNA üzerinde protein sentezi yapılabilir. Böylece translasyon kapasitesi kullanılır."},{"t":"Sonuç","a":"Protein üretimi artar","d":"Yeterli ribozom ve aminoasit bulunduğunda artan mRNA sayısı protein üretimini artırır. Çünkü daha çok kalıptan daha çok protein yapılır. Bu nedenle transkripsiyon hızı protein miktarını etkiler."}],"ans":"mRNA sayısı arttığından protein sentezi de (kaynaklar yeterliyse) artar"},{"q":"Bir DNA kalıp ipliği 3'-A T G C T A G C-5' dizisindedir. Bu kalıptan oluşan mRNA'da kaç adet pürin bazı (adenin ve guanin) bulunur?","steps":[{"t":"mRNA dizisini bul","a":"Eşleşmeyi uygula","d":"Kalıptaki A-T-G-C-T-A-G-C dizisi için RNA karşılıkları bulunur. A'ya U, T'ye A, G'ye C, C'ye G, T'ye A, A'ya U, G'ye C, C'ye G eklenir. Böylece mRNA dizisi U A C G A U C G olur."},{"t":"Pürinleri tanı","a":"Adenin ve guanin","d":"Pürin bazları adenin ve guaninden oluşur, urasil ve sitozin ise pirimidindir. mRNA dizisindeki adenin ve guanin bazları pürin olarak sayılır. Diğer bazlar bu sayıya dahil edilmez."},{"t":"Pürin sayısı","a":"2 pürin","d":"U A C G A U C G dizisinde adenin sayısı 2, guanin sayısı 0 olarak görülür çünkü kalıptaki G'ler mRNA'da C'ye dönüşmüştür. Wait, yeniden sayılırsa A:2, G:0; toplam pürin 2'dir. Bu nedenle mRNA'da 2 pürin bazı bulunur."}],"ans":"2 pürin bazı"},{"q":"Bir mRNA molekülü 5'-A U G G G C U A A-3' dizisindedir. Bu mRNA'nın sentezlendiği DNA kalıp ipliğinin baz dizisini bulunuz ve yönünü belirtiniz.","steps":[{"t":"Ters tamamlama uygula","a":"mRNA'dan kalıba","d":"Kalıp iplik mRNA'nın tamamlayıcısıdır, bu yüzden ters eşleşme yapılır. mRNA'daki A karşısına T, U karşısına A, G karşısına C, C karşısına G gelir. RNA'daki urasil DNA'da adenin karşılığıdır."},{"t":"Kalıp bazlarını bul","a":"T A C C C G A T T","d":"mRNA'daki A U G G G C U A A dizisi için kalıp bazları bulunur. A'ya T, U'ya A, G'ye C, G'ye C, G'ye C, C'ye G, U'ya A, A'ya T, A'ya T eklenir. Böylece kalıp dizisi belirlenir."},{"t":"Yönü ayarla","a":"3'-T A C C C G A T T-5'","d":"Kalıp iplik mRNA'ya antiparaleldir, ters yönde yazılır. mRNA 5'-3' yönündeyse kalıp 3'-5' yönündedir. Sonuç 3'-T A C C C G A T T-5' olur."}],"ans":"3'-T A C C C G A T T-5'"},{"q":"Bir DNA bölgesinde anlamlı iplikteki guanin sayısı 45, sitozin sayısı 30'dur. Bu bölgeden sentezlenen mRNA'daki sitozin ve guanin sayılarını bulunuz.","steps":[{"t":"Anlamlı iplik - mRNA","a":"Aynı diziye sahip","d":"Anlamlı iplik ile mRNA aynı baz dizisine sahiptir, yalnızca timin urasile dönüşür. Guanin ve sitozin her ikisinde de değişmeden kalır. Bu nedenle bu bazların sayıları doğrudan aktarılır."},{"t":"Guanin sayısı","a":"mRNA'da 45 guanin","d":"Anlamlı iplikteki guanin, mRNA'da da guanin olarak kalır. Anlamlı iplikte 45 guanin olduğundan mRNA'da da 45 guanin bulunur. Sayı değişmez."},{"t":"Sitozin sayısı","a":"mRNA'da 30 sitozin","d":"Anlamlı iplikteki sitozin, mRNA'da da sitozin olarak kalır. Anlamlı iplikte 30 sitozin olduğundan mRNA'da da 30 sitozin bulunur. Böylece guanin 45, sitozin 30 olur."}],"ans":"mRNA'da 45 guanin ve 30 sitozin bulunur"},{"q":"Transkripsiyonda RNA polimeraz primer (başlatıcı) gerektirmezken DNA replikasyonunda DNA polimeraz primer gerektirir. Bu farkın işleyişe etkisini açıklayınız.","steps":[{"t":"RNA polimerazın yeteneği","a":"Kendi başlatabilir","d":"RNA polimeraz, RNA sentezini başlatmak için önceden var olan bir zincire ihtiyaç duymaz. Yani sentezi sıfırdan başlatabilir. Bu nedenle transkripsiyonda primer gerekmez."},{"t":"DNA polimerazın ihtiyacı","a":"Primer ister","d":"DNA polimeraz, sentezi başlatmak için 3' ucu serbest bir başlatıcı zincire ihtiyaç duyar. Bu başlatıcıya primer denir ve genellikle RNA yapılıdır. Primer olmadan DNA sentezi başlamaz."},{"t":"İşleyişe etkisi","a":"Replikasyon daha karmaşık","d":"Primer gerekliliği, replikasyonu transkripsiyona göre daha çok basamaklı yapar. Replikasyonda primerler sonradan çıkarılıp DNA ile doldurulur. Transkripsiyon ise bu ek basamağı içermez."}],"ans":"RNA polimeraz primer gerektirmediğinden transkripsiyon doğrudan başlar; replikasyon primer nedeniyle daha çok basamaklıdır"},{"q":"Bir mRNA molekülünde adenin sayısı urasil sayısının iki katıdır ve toplam baz sayısı 300'dür. Guanin ile sitozin sayıları eşit ve toplamları 120 ise, mRNA'daki adenin sayısını bulunuz.","steps":[{"t":"A ve U dışı bazlar","a":"A + U = 180","d":"mRNA'da toplam baz sayısı 300'dür ve guanin ile sitozin toplamı 120'dir. Geriye kalan bazlar adenin ve urasildir. Bu nedenle adenin ile urasil toplamı 300 eksi 120, yani 180'dir."},{"t":"A-U ilişkisini kur","a":"A = 2U","d":"Adenin sayısının urasil sayısının iki katı olduğu verilmiştir. Yani A eşittir 2U yazılır. Toplam A artı U 180 olduğundan 2U artı U eşittir 180 olur."},{"t":"Adenini hesapla","a":"U = 60, A = 120","d":"3U eşittir 180 denkleminden urasil 60 bulunur. Adenin urasilin iki katı olduğundan 2 çarpı 60 eşittir 120 olur. Böylece mRNA'daki adenin sayısı 120'dir."}],"ans":"120 adenin"},{"q":"Bir bilim insanı, bir hücrede RNA polimeraz enzimini etkisiz hâle getiren bir madde uyguluyor. Bu durumun gen anlatımı ve protein sentezi üzerindeki sonucunu açıklayınız.","steps":[{"t":"Enzimin görevi durur","a":"mRNA üretilemez","d":"RNA polimeraz transkripsiyonu yürüten enzimdir ve etkisiz hâle gelirse transkripsiyon gerçekleşemez. Bu durumda DNA'daki bilgi mRNA'ya kopyalanamaz. Yani yeni mRNA üretimi durur."},{"t":"Translasyon etkilenir","a":"Kalıp bulunamaz","d":"Protein sentezi için ribozomun okuyacağı mRNA gereklidir. mRNA üretilemediğinde translasyon için kalıp kalmaz. Mevcut mRNA'lar tükendikçe yeni protein üretimi durur."},{"t":"Genel sonuç","a":"Protein sentezi durur","d":"mRNA olmadan protein sentezi sürdürülemez ve hücre işlevlerini yerine getiremez hâle gelir. Çünkü transkripsiyon gen anlatımının zorunlu ilk basamağıdır. Bu nedenle enzimin durması tüm süreci durdurur."}],"ans":"Transkripsiyon durur, mRNA üretilemez ve buna bağlı olarak protein sentezi de durur"}]}},"translasyon":{"ilkokul":{"kolay":[{"q":"Hücrede proteinler üretilir. Bu üretim mRNA'daki bilgi okunarak yapılır. Protein üretiminin yapıldığı küçük yapıya ne ad verilir?","steps":[{"t":"Protein nedir?","a":"Vücudun yapı taşı","d":"Proteinler vücudumuzun yapı taşlarıdır ve birçok görevi vardır. Bu proteinler hücre içinde üretilir. Üretim için özel bir yer gerekir."},{"t":"Üretim yeri","a":"Ribozomda yapılır","d":"Protein üretimi ribozom adı verilen küçük yapılarda yapılır. Ribozom, mRNA'daki bilgiyi okuyarak protein üretir. Bu nedenle ribozom protein fabrikası gibidir."}],"ans":"Ribozom"},{"q":"Protein üretimi sırasında mRNA'daki bilgi okunur. mRNA'daki bilgiyi kullanarak proteini oluşturan bu olaya ne ad verilir?","steps":[{"t":"mRNA bilgi taşır","a":"Bilgi okunur","d":"mRNA, DNA'dan aldığı bilgiyi ribozoma taşır. Ribozom bu bilgiyi okur. Okunan bilgi protein üretmek için kullanılır."},{"t":"Olayın adı","a":"Translasyon denir","d":"mRNA'daki bilginin okunarak proteine çevrilmesine translasyon denir. Bu kelime çeviri anlamına gelir. Çünkü bilgi protein diline çevrilir."}],"ans":"Translasyon (çeviri)"},{"q":"Proteinler küçük yapı taşlarından oluşur. Proteini oluşturan ve birbirine eklenen bu küçük yapı taşlarına ne ad verilir?","steps":[{"t":"Protein parçalardan oluşur","a":"Küçük taşlar birleşir","d":"Proteinler tek bir parça değildir, küçük yapı taşlarının birleşmesinden oluşur. Bu taşlar arka arkaya dizilir. Böylece protein meydana gelir."},{"t":"Yapı taşının adı","a":"Aminoasit denir","d":"Proteini oluşturan küçük yapı taşlarına aminoasit denir. Aminoasitler bir araya gelerek proteini yapar. Bir kolyenin boncukları gibi dizilirler."}],"ans":"Aminoasit"},{"q":"Translasyon sırasında aminoasitleri ribozoma taşıyan özel bir RNA vardır. Bu taşıyıcı RNA çeşidinin adı nedir?","steps":[{"t":"Aminoasit taşınmalı","a":"Taşıyıcı gerekir","d":"Protein üretmek için aminoasitlerin ribozoma getirilmesi gerekir. Bu işi yapan özel bir taşıyıcı vardır. Taşıyıcı bir RNA çeşididir."},{"t":"Taşıyıcının adı","a":"tRNA taşır","d":"Aminoasitleri ribozoma taşıyan RNA'ya taşıyıcı RNA yani tRNA denir. tRNA doğru aminoasidi getirir. Böylece protein doğru şekilde yapılır."}],"ans":"tRNA (taşıyıcı RNA)"},{"q":"Translasyon işlemi hücrenin belirli bir bölümünde gerçekleşir. Ribozomların bulunduğu ve protein üretiminin yapıldığı bu bölüm neresidir?","steps":[{"t":"Ribozomun yeri","a":"Hücre sıvısında","d":"Ribozomlar genellikle hücrenin sıvı kısmında bulunur. Bu sıvı kısma sitoplazma denir. Protein üretimi burada yapılır."},{"t":"Üretim yeri","a":"Sitoplazmada olur","d":"Translasyon, ribozomların bulunduğu sitoplazmada gerçekleşir. mRNA çekirdekten buraya gelir. Burada protein üretimi tamamlanır."}],"ans":"Sitoplazmada"}],"zor":[{"q":"mRNA üzerindeki bilgiler üçer üçer gruplar hâlinde okunur. Bir aminoasidi belirleyen bu üç bazlık mRNA grubuna ne ad verilir?","steps":[{"t":"mRNA üçer okunur","a":"Üçlü gruplar","d":"mRNA üzerindeki bazlar tek tek değil üçer üçer gruplanarak okunur. Her grup bir bilgi taşır. Bu gruplar protein için önemlidir."},{"t":"Grubun görevi","a":"Aminoasit belirler","d":"Üç bazlık her grup, bir aminoasidi belirler. Yani hangi aminoasidin ekleneceğini söyler. Böylece protein doğru yapılır."},{"t":"Grubun adı","a":"Kodon denir","d":"mRNA'daki bir aminoasidi belirleyen üç bazlık gruba kodon denir. Her kodon bir aminoaside karşılık gelir. Kodonlar protein şifresidir."}],"ans":"Kodon"},{"q":"tRNA'nın ucunda mRNA kodonuyla eşleşen üç bazlık özel bir bölge vardır. tRNA'daki bu üç bazlık bölgenin adı nedir?","steps":[{"t":"tRNA kodona uyar","a":"Eşleşme gerekir","d":"tRNA, doğru yere oturabilmek için mRNA'daki kodona uymalıdır. Bunun için tRNA'nın üzerinde özel bir bölge bulunur. Bu bölge kodonla eşleşir."},{"t":"Bölgenin görevi","a":"Kodonla eşleşir","d":"tRNA'nın üzerindeki üç bazlık bölge, mRNA kodonu ile baz eşleşmesi yapar. Böylece doğru tRNA doğru kodona oturur. Bu eşleşme proteinin doğru olmasını sağlar."},{"t":"Bölgenin adı","a":"Antikodon denir","d":"tRNA'daki üç bazlık bu bölgeye antikodon denir. Antikodon, mRNA kodonunun tamamlayıcısıdır. Her tRNA'nın kendi antikodonu vardır."}],"ans":"Antikodon"},{"q":"Protein sentezinin başlamasını sağlayan özel bir kodon vardır. Translasyonun başladığı bu kodon hangisidir?","steps":[{"t":"Başlangıç gerekir","a":"Özel kodon vardır","d":"Protein sentezi rastgele bir yerden başlamaz, belirli bir kodondan başlar. Bu özel kodon başlangıcı işaret eder. Ribozom buradan okumaya başlar."},{"t":"Başlangıç kodonu","a":"AUG kodonu","d":"Translasyon AUG kodonu ile başlar ve bu kodon başlangıcı belirtir. AUG aynı zamanda metiyonin aminoasidini de taşır. Bu nedenle protein sentezi AUG'den başlar."}],"ans":"AUG (başlangıç kodonu)"},{"q":"Aminoasitler birbirine eklenirken aralarında özel bir bağ kurulur. İki aminoasidi birbirine bağlayan bu bağa ne ad verilir?","steps":[{"t":"Aminoasitler birleşir","a":"Bağ kurulur","d":"Protein yapmak için aminoasitler birbirine eklenir. Bu eklenme sırasında aralarında bir bağ oluşur. Bu bağ aminoasitleri birbirine tutturur."},{"t":"Bağın adı","a":"Peptit bağı","d":"İki aminoasidi birbirine bağlayan bağa peptit bağı denir. Bu bağ sayesinde aminoasitler zincir oluşturur. Böylece protein meydana gelir."}],"ans":"Peptit bağı"},{"q":"Translasyon sonucunda birçok aminoasit birbirine bağlanarak uzun bir zincir oluşturur. Bu işlem sonucunda meydana gelen aminoasit zincirine ne ad verilir?","steps":[{"t":"Aminoasitler dizilir","a":"Zincir oluşur","d":"Translasyonda aminoasitler peptit bağlarıyla arka arkaya dizilir. Bu dizilme uzun bir zincir meydana getirir. Zincir giderek uzar."},{"t":"Zincirin adı","a":"Polipeptit denir","d":"Birçok aminoasidin bağlanmasıyla oluşan zincire polipeptit denir. Polipeptit katlanarak proteini oluşturur. Yani protein polipeptitlerden meydana gelir."}],"ans":"Polipeptit (protein zinciri)"}]},"ortaokul":{"kolay":[{"q":"Translasyon, mRNA'daki bilginin proteine çevrildiği olaydır. Bu olayın gerçekleştiği ve mRNA'nın okunduğu hücre yapısı hangisidir?","steps":[{"t":"mRNA okunmalı","a":"Bir yapı gerekir","d":"Translasyon için mRNA'nın okunması gerekir. Bu okuma işlemi özel bir yapıda yapılır. Bu yapı protein üretiminin merkezidir."},{"t":"Okuma yeri","a":"Ribozomda olur","d":"mRNA, ribozomda okunarak proteine çevrilir. Ribozom hem büyük hem küçük alt birimden oluşur. Bu nedenle translasyon ribozomda gerçekleşir."}],"ans":"Ribozom"},{"q":"mRNA üzerindeki bilgi üçlü baz grupları hâlinde okunur. Bir aminoasidi belirleyen üç nükleotitlik mRNA birimine ne ad verilir?","steps":[{"t":"Üçlü okuma","a":"Bazlar gruplanır","d":"mRNA üzerindeki bazlar protein sentezinde üçer üçer gruplanır. Her grup bir bilgi birimi oluşturur. Bu birimler protein şifresini taşır."},{"t":"Birimin adı","a":"Kodon denir","d":"mRNA'daki üç nükleotitlik birime kodon denir ve her kodon bir aminoasidi belirler. Kodonlar genetik şifreyi oluşturur. Ribozom kodonları sırayla okur."}],"ans":"Kodon"},{"q":"tRNA'nın bir ucunda kodonla eşleşen, diğer ucunda ise bir aminoasit bulunur. tRNA'nın mRNA kodonu ile eşleşen üçlü baz dizisine ne ad verilir?","steps":[{"t":"tRNA'nın görevi","a":"Aminoasit taşır","d":"tRNA, ribozoma aminoasit getiren taşıyıcı moleküldür. Bir ucunda aminoasit taşır. Diğer ucunda ise mRNA ile eşleşen bir bölge bulunur."},{"t":"Eşleşen bölge","a":"Antikodon adı","d":"tRNA'nın mRNA kodonuyla eşleşen üçlü baz dizisine antikodon denir. Antikodon, kodonun tamamlayıcısıdır. Bu eşleşme doğru aminoasidin yerleşmesini sağlar."}],"ans":"Antikodon"},{"q":"Translasyon belirli bir kodonla başlar ve protein sentezini başlatır. Translasyonun başlama kodonu hangisidir ve hangi aminoasidi belirtir?","steps":[{"t":"Başlangıç gerekli","a":"Özel kodon var","d":"Protein sentezi mRNA üzerinde belirli bir noktadan başlar. Bu noktayı belirleyen özel bir kodon vardır. Ribozom buradan okumaya başlar."},{"t":"AUG kodonu","a":"Metiyonini belirtir","d":"Translasyonun başlangıç kodonu AUG'dir ve metiyonin aminoasidini belirtir. Bu kodon proteinin başlamasını sağlar. Çoğu proteinin ilk aminoasidi metiyonindir."}],"ans":"AUG kodonu; metiyonin aminoasidini belirtir"},{"q":"Translasyon sonucunda aminoasitler birbirine bağlanarak protein oluşur. Aminoasitler arasında kurulan ve onları birbirine bağlayan bağ hangisidir?","steps":[{"t":"Aminoasitler bağlanır","a":"Bağ oluşur","d":"Ribozomda aminoasitler arka arkaya dizilir ve birbirine bağlanır. Bu bağlanma sırasında özel bir kimyasal bağ kurulur. Bu bağ zinciri oluşturur."},{"t":"Bağın adı","a":"Peptit bağı","d":"Aminoasitleri birbirine bağlayan bağa peptit bağı denir. Bu bağ sayesinde polipeptit zinciri uzar. Böylece protein meydana gelir."}],"ans":"Peptit bağı"}],"zor":[{"q":"Bir mRNA dizisi 5'-A U G G C A U A A-3' şeklindedir. Bu mRNA kaç kodondan oluşur ve hangi kodonla protein sentezi başlar?","steps":[{"t":"Kodonlara ayır","a":"Üçer baz grupla","d":"mRNA, protein sentezinde üçer baz hâlinde okunur. Bu nedenle dizi üçerli gruplara ayrılır. A U G, G C A ve U A A şeklinde üç grup oluşur."},{"t":"Kodon sayısı","a":"3 kodon","d":"mRNA'daki 9 baz, üçer üçer gruplanınca 3 kodon elde edilir. Her kodon üç bazdan oluşur. Bu nedenle bu mRNA 3 kodon içerir."},{"t":"Başlangıç kodonu","a":"AUG ile başlar","d":"Protein sentezi başlangıç kodonu olan AUG ile başlar. Dizideki ilk kodon AUG'dir. Bu nedenle sentez bu kodondan başlar."}],"ans":"3 kodon vardır; AUG ile başlar"},{"q":"Bir mRNA kodonu 5'-G C A-3' şeklindedir. Bu kodonu okuyan tRNA'nın antikodon baz dizisini bulunuz.","steps":[{"t":"Kodon-antikodon ilişkisi","a":"Tamamlayıcı eşleşir","d":"tRNA'nın antikodonu, mRNA kodonunun tamamlayıcısıdır. Bazlar arasında A-U, G-C eşleşmesi geçerlidir. Antikodon kodona ters yönde bağlanır."},{"t":"Karşılıkları bul","a":"C G U bazları","d":"mRNA kodonu G C A için antikodon bazları bulunur. G karşısına C, C karşısına G, A karşısına U gelir. Böylece antikodon bazları belirlenir."},{"t":"Antikodon yönü","a":"3'-C G U-5'","d":"Antikodon, kodona antiparalel olarak bağlanır. mRNA kodonu 5'-3' ise antikodon 3'-5' yönündedir. Sonuç 3'-C G U-5' olur."}],"ans":"3'-C G U-5'"},{"q":"Bir polipeptit zinciri 50 aminoasitten oluşmaktadır. Bu polipeptidi kodlayan mRNA'da en az kaç kodon (durdurma kodonu hariç) aminoasit belirler?","steps":[{"t":"Kodon-aminoasit ilişkisi","a":"Her kodon bir aminoasit","d":"Translasyonda her kodon bir aminoasidi belirler. Polipeptitteki her aminoasit için bir kodon gereklidir. Bu nedenle aminoasit sayısı kodon sayısını verir."},{"t":"Kodon sayısı","a":"50 kodon","d":"Polipeptit 50 aminoasitten oluştuğuna göre, bunları belirleyen 50 kodon vardır. Her aminoasit bir kodonla eşleşir. Durdurma kodonu aminoasit belirlemediğinden bu sayıya dahil edilmez."}],"ans":"50 kodon"},{"q":"Translasyon sırasında protein sentezinin durması gerekir. Ribozomun protein sentezini sonlandırmasına neden olan kodonların ortak özelliği nedir?","steps":[{"t":"Durdurma gerekli","a":"Özel kodon var","d":"Protein sentezi sonsuza kadar devam etmez, belirli bir noktada durur. Bu durmayı sağlayan özel kodonlar vardır. Ribozom bu kodonlara ulaşınca durur."},{"t":"Durdurma kodonları","a":"Aminoasit taşımaz","d":"Durdurma kodonları olan UAA, UAG ve UGA hiçbir aminoasidi belirlemez. Bu kodonlara karşılık gelen bir tRNA yoktur. Bu nedenle sentez bu noktada sonlanır."},{"t":"Sonuç","a":"Protein tamamlanır","d":"Durdurma kodonuna gelindiğinde ribozom polipeptidi serbest bırakır ve sentez biter. Böylece protein tamamlanmış olur. Durdurma kodonları aminoasit içermediği için ortak özellikleri budur."}],"ans":"Durdurma kodonları (UAA, UAG, UGA) hiçbir aminoasit belirlemez"},{"q":"Bir mRNA dizisi 5'-A U G U U U G G A U A A-3' şeklindedir. Bu mRNA'dan kaç aminoasitlik bir polipeptit sentezlenir?","steps":[{"t":"Kodonlara ayır","a":"Dört kodon var","d":"mRNA üçer baz hâlinde okunur ve dizi gruplara ayrılır. A U G, U U U, G G A ve U A A olmak üzere dört kodon elde edilir. Her kodon ayrı bir bilgi taşır."},{"t":"Durdurma kodonunu bul","a":"UAA durdurur","d":"Dizideki UAA kodonu bir durdurma kodonudur ve aminoasit belirlemez. Bu kodon protein sentezini sonlandırır. Bu nedenle UAA polipeptide aminoasit eklemez."},{"t":"Aminoasit sayısı","a":"3 aminoasit","d":"Dört kodondan biri durdurma kodonu olduğundan aminoasit belirleyen üç kodon kalır. AUG, UUU ve GGA birer aminoasit belirler. Böylece 3 aminoasitlik polipeptit oluşur."}],"ans":"3 aminoasit"}]},"lise":{"kolay":[{"q":"Translasyon, gen anlatımının ikinci basamağıdır. Bu olayda mRNA'daki bilgi neye çevrilir ve işlem hangi yapıda gerçekleşir?","steps":[{"t":"Gen anlatımı","a":"İkinci basamak","d":"Gen anlatımı transkripsiyon ve translasyon olarak iki basamaktan oluşur. Translasyon bu sürecin ikinci adımıdır. Burada mRNA bilgisi kullanılır."},{"t":"Çeviri ürünü","a":"Protein oluşur","d":"Translasyonda mRNA'daki kodon dizisi okunarak aminoasit dizisine yani proteine çevrilir. Bu nedenle olaya çeviri denir. Sonuçta bir polipeptit oluşur."},{"t":"Gerçekleşme yeri","a":"Ribozomda olur","d":"Translasyon, sitoplazmada bulunan ribozomlarda gerçekleşir. Ribozom mRNA'yı okur ve tRNA'ların getirdiği aminoasitleri birleştirir. Böylece protein sentezi tamamlanır."}],"ans":"mRNA bilgisi proteine çevrilir; ribozomda gerçekleşir"},{"q":"Translasyonda tRNA molekülleri kilit rol oynar. Bir tRNA molekülünün iki ucunda taşıdığı temel görevler nelerdir?","steps":[{"t":"tRNA yapısı","a":"İki uç önemli","d":"tRNA, üç boyutlu özel bir yapıya sahip küçük bir RNA molekülüdür. Bu yapının iki ucu farklı görevler taşır. Her uç translasyon için önemlidir."},{"t":"Aminoasit ucu","a":"Aminoasit bağlanır","d":"tRNA'nın bir ucuna belirli bir aminoasit bağlanır. Bu aminoasit ribozoma taşınır. Her tRNA kendine özgü aminoasidi taşır."},{"t":"Antikodon ucu","a":"Kodonla eşleşir","d":"tRNA'nın diğer ucunda antikodon bulunur ve bu antikodon mRNA kodonuyla eşleşir. Böylece doğru aminoasit doğru yere yerleştirilir. Bu eşleşme proteinin doğruluğunu sağlar."}],"ans":"Bir ucunda aminoasit taşır, diğer ucundaki antikodon ile mRNA kodonuna eşleşir"},{"q":"Translasyonda mRNA kodonları ile tRNA antikodonları belirli bir kurala göre eşleşir. Bu eşleşmede A bazının karşısına gelen baz hangisidir?","steps":[{"t":"Kodon-antikodon eşleşmesi","a":"Baz kuralı","d":"mRNA kodonu ile tRNA antikodonu tamamlayıcı baz eşleşmesi yapar. Bu eşleşmede A-U ve G-C kuralı geçerlidir. RNA molekülleri arasında timin bulunmaz."},{"t":"A bazının karşılığı","a":"U ile eşleşir","d":"Eşleşmede adenin bazının karşısına urasil gelir. Çünkü RNA'da timin yerine urasil bulunur. Bu nedenle A ile U eşleşir."}],"ans":"Urasil (U)"},{"q":"Translasyon belirli bir kodonla başlar. Protein sentezini başlatan kodon hangisidir ve genellikle hangi aminoasidi taşır?","steps":[{"t":"Başlangıç kodonu","a":"AUG belirler","d":"Translasyon başlangıç kodonu olan AUG ile başlar. Bu kodon ribozoma nereden okumaya başlayacağını söyler. Sentez bu kodondan ileri doğru ilerler."},{"t":"Taşınan aminoasit","a":"Metiyonin gelir","d":"AUG kodonu genellikle metiyonin aminoasidini belirtir. Bu nedenle çoğu polipeptidin ilk aminoasidi metiyonindir. Sentez başlarken bu aminoasit eklenir."}],"ans":"AUG kodonu; metiyonin aminoasidini taşır"},{"q":"Translasyonda aminoasitler arasında özel bir kovalent bağ kurulur. İki aminoasit arasında oluşan ve polipeptit zincirini meydana getiren bağ hangisidir?","steps":[{"t":"Aminoasit birleşmesi","a":"Bağ kurulur","d":"Ribozomda aminoasitler arka arkaya getirilerek birleştirilir. Bu birleşme sırasında kovalent bir bağ oluşur. Bu bağ aminoasitleri birbirine kalıcı olarak bağlar."},{"t":"Bağın adı","a":"Peptit bağı","d":"İki aminoasit arasında oluşan bağa peptit bağı denir. Bu bağ bir aminoasidin karboksil grubu ile diğerinin amino grubu arasında kurulur. Peptit bağlarıyla polipeptit zinciri uzar."}],"ans":"Peptit bağı"},{"q":"Translasyonun sonlanması özel kodonlarla sağlanır. Protein sentezini durduran durdurma (stop) kodonları hangileridir?","steps":[{"t":"Sonlanma gerekli","a":"Özel kodonlar","d":"Protein sentezi belirli bir noktada durmalıdır. Bu durmayı sağlayan üç özel kodon vardır. Ribozom bu kodonlara ulaşınca sentezi bitirir."},{"t":"Durdurma kodonları","a":"UAA, UAG, UGA","d":"Durdurma kodonları UAA, UAG ve UGA'dır ve hiçbiri aminoasit belirlemez. Bu kodonlara karşılık gelen tRNA yoktur. Bu nedenle ribozom polipeptidi serbest bırakır."}],"ans":"UAA, UAG ve UGA"},{"q":"Translasyon birden fazla RNA çeşidinin ortak çalışmasını gerektirir. Protein sentezinde görev alan üç RNA çeşidi ve genel görevleri nelerdir?","steps":[{"t":"mRNA görevi","a":"Kalıp taşır","d":"mRNA, DNA'dan aldığı bilgiyi kodonlar hâlinde ribozoma taşır. Protein sentezinde kalıp görevi görür. Aminoasit dizisini belirleyen bilgiyi içerir."},{"t":"tRNA görevi","a":"Aminoasit getirir","d":"tRNA, sitoplazmadaki aminoasitleri ribozoma taşır. Antikodonu sayesinde doğru kodona yerleşir. Böylece doğru aminoasit zincire eklenir."},{"t":"rRNA görevi","a":"Ribozom yapısında","d":"rRNA, ribozomun yapısına katılır ve protein sentezinde yapısal ve işlevsel rol oynar. Ribozomun çalışmasını sağlar. Bu üç RNA birlikte translasyonu yürütür."}],"ans":"mRNA kalıp taşır, tRNA aminoasit getirir, rRNA ribozom yapısında görev alır"},{"q":"Bir mRNA molekülü ribozomda belirli bir yönde okunur. Ribozom mRNA'yı hangi uçtan hangi uca doğru okur?","steps":[{"t":"Okuma yönü kavramı","a":"Belirli yön var","d":"mRNA ribozomda rastgele değil belirli bir yönde okunur. Bu yön kodonların sırasını belirler. Okuma yönü protein dizisini etkiler."},{"t":"Okuma yönü","a":"5' ucundan 3' ucuna","d":"Ribozom mRNA'yı 5' ucundan 3' ucuna doğru okur. İlk okunan kodon başlangıç kodonudur. Okuma bu yönde durdurma kodonuna kadar devam eder."}],"ans":"5' ucundan 3' ucuna doğru"},{"q":"Translasyon sırasında ribozom mRNA üzerinde ilerler. Bir kodon okunup aminoasit eklendikten sonra ribozom ne yapar?","steps":[{"t":"Kodon okunur","a":"Aminoasit eklenir","d":"Ribozom mRNA üzerindeki bir kodonu okur ve uygun tRNA aminoasidi getirir. Bu aminoasit zincire peptit bağıyla eklenir. Böylece polipeptit uzar."},{"t":"Ribozom ilerler","a":"Sonraki kodona geçer","d":"Bir aminoasit eklendikten sonra ribozom bir kodon ileri kayar. Yeni kodonu okumaya hazır hâle gelir. Bu işlem durdurma kodonuna kadar tekrarlanır."}],"ans":"Ribozom bir sonraki kodona ilerler (kayar)"},{"q":"Translasyon tamamlandığında oluşan polipeptit işlevsel olmayabilir. Sentezlenen polipeptidin işlevsel bir protein hâline gelmesi için ne gerekir?","steps":[{"t":"Polipeptit oluşur","a":"Düz zincir","d":"Translasyon sonucunda aminoasitler düz bir zincir hâlinde dizilir. Bu zincire polipeptit denir. Ancak bu hâliyle henüz işlevsel değildir."},{"t":"Katlanma gerekir","a":"Üç boyut kazanır","d":"Polipeptit zinciri belirli bir şekilde katlanarak üç boyutlu yapı kazanır. Bu katlanma proteinin görevini yapabilmesi için gereklidir. Doğru katlanma işlevsel protein oluşturur."}],"ans":"Polipeptidin üç boyutlu yapısını kazanacak şekilde katlanması gerekir"},{"q":"Translasyon hücrenin enerji ve yapı taşı kaynaklarını kullanır. Protein sentezinin sürdürülebilmesi için ortamda hangi temel yapı taşları bulunmalıdır?","steps":[{"t":"Protein yapı taşı","a":"Aminoasit gerekir","d":"Proteinler aminoasitlerden oluşur, bu nedenle sentez için yeterli aminoasit bulunmalıdır. Aminoasitler tRNA'lar tarafından taşınır. Aminoasit yoksa zincir uzayamaz."},{"t":"Diğer ihtiyaçlar","a":"mRNA, tRNA, ribozom","d":"Sentez için kalıp olan mRNA, taşıyıcı olan tRNA ve okuma yapan ribozom gereklidir. Ayrıca enzimler ve enerji de gerekir. Bunlar bir arada bulunmalıdır."}],"ans":"Aminoasitler (ayrıca mRNA, tRNA, ribozom ve enerji)"},{"q":"Genetik şifrede AUG kodonu hem başlangıç hem de aminoasit görevi taşır. AUG kodonunun translasyondaki bu çift görevini açıklayınız.","steps":[{"t":"Başlangıç görevi","a":"Sentezi başlatır","d":"AUG kodonu, mRNA üzerinde protein sentezinin başlayacağı noktayı belirtir. Ribozom bu kodonu tanıyarak okumaya başlar. Bu nedenle başlangıç kodonu olarak görev yapar."},{"t":"Aminoasit görevi","a":"Metiyonin belirtir","d":"AUG kodonu aynı zamanda metiyonin aminoasidini belirtir. Yani başlangıçta zincire metiyonin eklenir. Dizinin iç kısmındaki AUG de metiyonin kodlar."}],"ans":"AUG hem sentezi başlatır hem de metiyonin aminoasidini belirtir"},{"q":"Translasyonda kodon ile antikodon arasındaki eşleşme çok önemlidir. Bu eşleşmenin doğru protein üretimindeki rolü nedir?","steps":[{"t":"Eşleşme kuralı","a":"Tamamlayıcı bazlar","d":"mRNA kodonu ile tRNA antikodonu tamamlayıcı baz eşleşmesi yapar. Bu eşleşme A-U ve G-C kurallarına uyar. Doğru eşleşme doğru tRNA'nın gelmesini sağlar."},{"t":"Doğru aminoasit","a":"Sıralama belirlenir","d":"Her tRNA belirli bir aminoasit taşıdığından, doğru antikodon eşleşmesi doğru aminoasidin eklenmesini sağlar. Böylece aminoasit sırası mRNA bilgisine uygun olur. Yanlış eşleşme yanlış protein oluşturur."}],"ans":"Doğru kodon-antikodon eşleşmesi, doğru aminoasit sırasını ve dolayısıyla doğru proteini sağlar"},{"q":"Translasyon ile transkripsiyon ardışık iki olaydır. Bu iki olayı yer, ürün ve kalıp açısından kısaca karşılaştırınız.","steps":[{"t":"Yer farkı","a":"Çekirdek - sitoplazma","d":"Transkripsiyon ökaryotlarda çekirdekte gerçekleşir. Translasyon ise sitoplazmadaki ribozomlarda olur. Yani iki olay farklı yerlerde gerçekleşir."},{"t":"Ürün farkı","a":"mRNA - protein","d":"Transkripsiyonun ürünü mRNA, translasyonun ürünü ise proteindir. Transkripsiyon bilgiyi kopyalar, translasyon bu bilgiyi proteine çevirir. Ürünler birbirini takip eder."},{"t":"Kalıp farkı","a":"DNA - mRNA","d":"Transkripsiyonda kalıp DNA, translasyonda kalıp mRNA'dır. Transkripsiyon DNA'yı okur, translasyon mRNA'yı okur. Böylece kalıplar farklılaşır."}],"ans":"Transkripsiyon çekirdekte DNA'dan mRNA üretir; translasyon sitoplazmada mRNA'dan protein üretir"},{"q":"Genetik şifre evrensel kabul edilir. Aynı mRNA kodonunun farklı canlılarda aynı aminoasidi belirtmesi neyi gösterir?","steps":[{"t":"Şifrenin ortaklığı","a":"Kodonlar aynı","d":"Bakteriden insana kadar canlıların büyük çoğunluğunda aynı kodon aynı aminoasidi belirtir. Yani genetik şifre canlılar arasında ortaktır. Bu özelliğe şifrenin evrenselliği denir."},{"t":"Ne gösterir?","a":"Ortak köken","d":"Genetik şifrenin ortak olması, canlıların ortak bir kökenden geldiğini destekler. Çünkü farklı türler aynı çeviri sistemini kullanır. Bu durum yaşamın temel birliğini gösterir."}],"ans":"Genetik şifrenin evrensel olduğunu ve canlıların ortak kökene sahip olduğunu gösterir"}],"zor":[{"q":"Bir mRNA dizisi 5'-A U G G C A U U U U A A-3' şeklindedir. Bu mRNA'dan sentezlenen polipeptidin kaç aminoasit içerdiğini belirleyiniz.","steps":[{"t":"Kodonlara ayır","a":"Dört kodon","d":"mRNA üçer baz hâlinde okunur ve dizi gruplara ayrılır. A U G, G C A, U U U ve U A A olmak üzere dört kodon oluşur. Her kodon ayrı bilgi taşır."},{"t":"Durdurma kodonunu bul","a":"UAA durdurur","d":"Son kodon olan UAA bir durdurma kodonudur ve aminoasit belirlemez. Bu kodon protein sentezini sonlandırır. Bu nedenle polipeptide aminoasit eklemez."},{"t":"Aminoasit sayısı","a":"3 aminoasit","d":"Dört kodondan biri durdurma kodonu olduğu için aminoasit belirleyen üç kodon kalır. AUG, GCA ve UUU birer aminoasit kodlar. Böylece polipeptit 3 aminoasit içerir."}],"ans":"3 aminoasit"},{"q":"Bir DNA kalıp ipliği 3'-T A C G G G A T T-5' dizisindedir. Bu genden oluşan mRNA'nın ilk iki kodonunu ve bunların okunma yönünü belirleyiniz.","steps":[{"t":"mRNA'yı sentezle","a":"Eşleşmeyi uygula","d":"Kalıp ipliğindeki her baz karşısına tamamlayıcı RNA bazı eklenir. T'ye A, A'ya U, C'ye G, G'ye C eklenir. Böylece kalıptaki T A C G G G A T T için mRNA bazları bulunur."},{"t":"mRNA dizisini bul","a":"A U G C C C U A A","d":"Kalıptaki dizinin karşılıkları sırayla A, U, G, C, C, C, U, A, A olarak yazılır. mRNA, kalıba antiparalel olduğundan 5'-A U G C C C U A A-3' şeklinde oluşur. Bu dizi okunmaya hazırdır."},{"t":"İlk iki kodon","a":"AUG ve CCC","d":"mRNA 5' ucundan 3' ucuna doğru üçer baz okunur. İlk kodon AUG, ikinci kodon CCC olur. Yani sentez AUG ile başlar ve CCC ile devam eder."}],"ans":"İlk iki kodon 5'-AUG-3' ve 5'-CCC-3'; mRNA 5' ucundan okunur"},{"q":"Bir mRNA kodonu 5'-U U C-3' şeklindedir. Bu kodonu okuyan tRNA'nın antikodonunu, bu antikodonu kodlayan DNA kalıp dizisini ve yönlerini belirleyiniz.","steps":[{"t":"Antikodonu bul","a":"Tamamlayıcı eşleşme","d":"tRNA antikodonu mRNA kodonunun tamamlayıcısıdır ve antiparalel bağlanır. mRNA'daki U karşısına A, C karşısına G gelir. Kodon 5'-U U C-3' için antikodon 3'-A A G-5' olur."},{"t":"mRNA ile DNA kalıbı","a":"Kalıp mRNA tamamlayıcısı","d":"mRNA kodonu DNA kalıbından sentezlendiğinden kalıp, mRNA'nın tamamlayıcısıdır. mRNA'daki U karşısına A, U karşısına A, C karşısına G gelir. Kalıp dizi 3'-A A G-5' olur."},{"t":"Yönleri belirle","a":"Antiparalel diziler","d":"Antikodon 3'-A A G-5' yönünde, DNA kalıbı da 3'-A A G-5' yönündedir. Her ikisi de mRNA kodonuna antiparaleldir. Bu nedenle yönler tutarlıdır."}],"ans":"Antikodon 3'-A A G-5'; DNA kalıp dizisi 3'-A A G-5'"},{"q":"Bir polipeptit 199 aminoasit içermektedir. Durdurma kodonunu da hesaba katarak bu polipeptidi kodlayan mRNA'nın en az kaç nükleotit içermesi gerektiğini bulunuz.","steps":[{"t":"Aminoasit kodonları","a":"199 kodon","d":"Her aminoasit bir kodonla belirlenir, bu nedenle 199 aminoasit için 199 kodon gereklidir. Bu kodonlar aminoasit eklenmesini sağlar. Başlangıç kodonu da bu sayıya dahildir."},{"t":"Durdurma kodonu ekle","a":"200 kodon","d":"Aminoasit kodlamayan ancak sentezi durduran bir durdurma kodonu eklenir. Böylece toplam kodon sayısı 200 olur. Durdurma kodonu da mRNA üzerinde yer kaplar."},{"t":"Nükleotit sayısı","a":"600 nükleotit","d":"Her kodon üç nükleotitten oluşur, bu nedenle 200 kodon 600 nükleotit demektir. 200 çarpı 3 işlemiyle sonuç bulunur. Böylece mRNA en az 600 nükleotit içerir."}],"ans":"600 nükleotit"},{"q":"Bir mRNA dizisi 5'-A U G C G A G C U U G A-3' şeklindedir. Bu mRNA'da kodlanan aminoasit sayısını ve protein sentezinin nerede durduğunu belirleyiniz.","steps":[{"t":"Kodonlara ayır","a":"Dört kodon","d":"mRNA üçer baz hâlinde okunur ve dizi gruplara ayrılır. A U G, C G A, G C U ve U G A olmak üzere dört kodon oluşur. Her grup bir kodon oluşturur."},{"t":"Durdurma kodonu","a":"UGA durdurur","d":"Dördüncü kodon olan UGA bir durdurma kodonudur ve aminoasit belirlemez. Bu kodon protein sentezini sonlandırır. Sentez bu noktada durur."},{"t":"Aminoasit sayısı","a":"3 aminoasit","d":"Dört kodondan biri durdurma kodonu olduğundan üç kodon aminoasit belirler. AUG, CGA ve GCU birer aminoasit kodlar. Böylece 3 aminoasitlik polipeptit oluşur ve UGA'da durur."}],"ans":"3 aminoasit kodlanır; sentez UGA durdurma kodonunda durur"},{"q":"Bir DNA anlamlı (kalıp olmayan) ipliği 5'-A T G A A A T A A-3' dizisindedir. Bu genden oluşan mRNA'yı, kodon sayısını ve aminoasit sayısını belirleyiniz.","steps":[{"t":"mRNA'yı bul","a":"T yerine U","d":"Anlamlı iplik mRNA ile aynı diziye sahiptir, sadece timinler urasile dönüşür. A T G A A A T A A dizisindeki timinler urasile çevrilir. Böylece mRNA 5'-A U G A A A U A A-3' olur."},{"t":"Kodonlara ayır","a":"Üç kodon","d":"mRNA üçer baz hâlinde okunur ve gruplara ayrılır. A U G, A A A ve U A A olmak üzere üç kodon oluşur. Her kodon ayrı bir bilgi taşır."},{"t":"Aminoasit sayısı","a":"2 aminoasit","d":"Üçüncü kodon olan UAA durdurma kodonudur ve aminoasit belirlemez. Geriye AUG ve AAA olmak üzere iki kodon kalır. Bunlar birer aminoasit kodladığından polipeptit 2 aminoasit içerir."}],"ans":"mRNA 5'-A U G A A A U A A-3'; 3 kodon vardır, 2 aminoasit kodlanır"},{"q":"Bir mRNA molekülünde 300 nükleotit bulunmaktadır. Bu mRNA'nın tamamı (durdurma kodonu dâhil) kodon olarak kullanılırsa, en fazla kaç aminoasitlik bir polipeptit oluşur?","steps":[{"t":"Kodon sayısı","a":"100 kodon","d":"Her kodon üç nükleotitten oluştuğundan 300 nükleotit 100 kodon demektir. 300 bölü 3 işlemiyle bu sayı bulunur. Yani mRNA 100 kodon içerir."},{"t":"Durdurma kodonunu çıkar","a":"Bir kodon aminoasitsiz","d":"Kodonlardan biri durdurma kodonudur ve aminoasit belirlemez. Bu kodon polipeptide aminoasit eklemez. Bu nedenle aminoasit sayısı bir eksiktir."},{"t":"Aminoasit sayısı","a":"99 aminoasit","d":"100 kodondan biri durdurma kodonu olduğu için 99 kodon aminoasit kodlar. Her biri bir aminoasit ekler. Böylece en fazla 99 aminoasitlik polipeptit oluşur."}],"ans":"99 aminoasit"},{"q":"Bir DNA kalıp ipliği 3'-T A C T T T A C T-5' dizisindedir. Bu genden oluşan polipeptidin aminoasit sayısını ve sentezin durup durmadığını açıklayınız.","steps":[{"t":"mRNA'yı sentezle","a":"Eşleşmeyi uygula","d":"Kalıptaki her baz karşısına tamamlayıcı RNA bazı eklenir. T'ye A, A'ya U, C'ye G eklenir. Kalıptaki T A C T T T A C T için mRNA 5'-A U G A A A U G A-3' olur."},{"t":"Kodonlara ayır","a":"Üç kodon","d":"mRNA üçer baz hâlinde gruplanır. A U G, A A A ve U G A olmak üzere üç kodon oluşur. Her kodon bir bilgi taşır."},{"t":"Aminoasit ve durma","a":"2 aminoasit; UGA durdurur","d":"Üçüncü kodon UGA bir durdurma kodonudur ve aminoasit belirlemez. AUG ve AAA iki aminoasit kodlar. Böylece polipeptit 2 aminoasit içerir ve sentez UGA'da durur."}],"ans":"2 aminoasit oluşur; sentez UGA durdurma kodonunda durur"},{"q":"Translasyon sırasında mRNA üzerinde tek bir nükleotit eklenmesi (insersiyon) okuma çerçevesini etkiler. Bu durumun protein üzerindeki olası etkisini açıklayınız.","steps":[{"t":"Okuma çerçevesi","a":"Üçerli okuma","d":"mRNA, başlangıç kodonundan itibaren üçerli gruplar hâlinde okunur ve bu gruplama okuma çerçevesini oluşturur. Her kodon belirli aminoaside karşılık gelir. Çerçeve bozulursa kodonlar değişir."},{"t":"Nükleotit eklenmesi","a":"Çerçeve kayar","d":"Tek bir nükleotit eklendiğinde ekleme noktasından sonraki tüm bazlar bir kayar. Bu durum çerçeve kayması olarak adlandırılır. Böylece sonraki tüm kodonlar değişir."},{"t":"Protein üzerine etki","a":"Farklı protein oluşur","d":"Çerçeve kayması nedeniyle ekleme sonrasındaki aminoasit dizisi tamamen değişir. Erken bir durdurma kodonu da oluşabilir ve protein kısa kalabilir. Sonuçta genellikle işlevsiz bir protein ortaya çıkar."}],"ans":"Okuma çerçevesi kayar; sonraki kodonlar değişir ve genellikle işlevsiz/farklı bir protein oluşur"},{"q":"Bir mRNA dizisi 5'-A U G U A C G G A C C U U G A-3' şeklindedir. Bu mRNA'nın aminoasit kodlayan kodon sayısını ve toplam kodon sayısını belirleyiniz.","steps":[{"t":"Kodonlara ayır","a":"Beş kodon","d":"mRNA üçer baz hâlinde gruplanır. A U G, U A C, G G A, C C U ve U G A olmak üzere beş kodon oluşur. Toplam 15 baz beş kodona ayrılır."},{"t":"Toplam kodon sayısı","a":"5 kodon","d":"Dizi 15 nükleotit içerir ve üçer üçer gruplanınca 5 kodon elde edilir. Bu kodonlardan biri durdurma kodonudur. Toplam kodon sayısı 5'tir."},{"t":"Aminoasit kodlayan kodonlar","a":"4 kodon","d":"Son kodon UGA bir durdurma kodonudur ve aminoasit belirlemez. Geriye AUG, UAC, GGA ve CCU olmak üzere dört kodon kalır. Bu nedenle aminoasit kodlayan kodon sayısı 4'tür."}],"ans":"Toplam 5 kodon vardır; bunlardan 4'ü aminoasit kodlar"},{"q":"Bir tRNA'nın antikodonu 3'-U A C-5' şeklindedir. Bu tRNA hangi kodonu okur ve bu kodon translasyonda hangi özel görevi taşır?","steps":[{"t":"Kodonu bul","a":"Tamamlayıcı eşleşme","d":"tRNA antikodonu mRNA kodonunun tamamlayıcısıdır ve antiparalel eşleşir. Antikodondaki U karşısına A, A karşısına U, C karşısına G gelir. Antikodon 3'-U A C-5' için kodon 5'-A U G-3' olur."},{"t":"Kodonun görevi","a":"Başlangıç kodonu","d":"Bulunan kodon AUG'dir ve bu kodon translasyonun başlangıç kodonudur. Protein sentezinin başladığı noktayı belirtir. Ayrıca metiyonin aminoasidini taşır."}],"ans":"Kodon 5'-A U G-3'; başlangıç kodonudur (metiyonini belirtir)"},{"q":"Bir hücrede bir mRNA üzerinde aynı anda birden fazla ribozom bağlanarak protein üretebilir. Bu yapının (polizom) protein sentezindeki avantajını açıklayınız.","steps":[{"t":"Polizom yapısı","a":"Çok ribozom","d":"Bir mRNA üzerinde aynı anda birçok ribozom bağlanarak ilerleyebilir. Bu yapıya polizom denir. Her ribozom mRNA'yı bağımsız okur."},{"t":"Eş zamanlı sentez","a":"Aynı anda üretim","d":"Polizomda her ribozom aynı mRNA'dan ayrı bir polipeptit sentezler. Yani tek mRNA'dan aynı anda birçok protein üretilir. Ribozomlar mRNA boyunca sıralanır."},{"t":"Avantajı","a":"Hız ve verim","d":"Polizom sayesinde aynı mRNA kalıbından kısa sürede çok sayıda protein üretilir. Bu durum protein sentezini hızlandırır ve verimi artırır. Hücre ihtiyaç duyduğu proteini hızla karşılar."}],"ans":"Tek bir mRNA'dan aynı anda çok sayıda protein üretilir; sentez hızlanır ve verim artar"},{"q":"Bir mRNA'nın baz dizisi 5'-A U G A G U C A C U A G-3' şeklindedir. Bu mRNA'dan oluşan polipeptidin aminoasit sayısını ve sentezin durduğu kodonu belirleyiniz.","steps":[{"t":"Kodonlara ayır","a":"Dört kodon","d":"mRNA üçer baz hâlinde gruplanır. A U G, A G U, C A C ve U A G olmak üzere dört kodon oluşur. Toplam 12 baz dört kodona ayrılır."},{"t":"Durdurma kodonu","a":"UAG durdurur","d":"Dördüncü kodon UAG bir durdurma kodonudur ve aminoasit belirlemez. Bu kodon protein sentezini sonlandırır. Sentez bu noktada durur."},{"t":"Aminoasit sayısı","a":"3 aminoasit","d":"Dört kodondan biri durdurma kodonu olduğundan üç kodon aminoasit belirler. AUG, AGU ve CAC birer aminoasit kodlar. Böylece polipeptit 3 aminoasit içerir."}],"ans":"3 aminoasit oluşur; sentez UAG durdurma kodonunda durur"},{"q":"Bir DNA geninde meydana gelen bir mutasyon sonucu mRNA'da bir kodon AUG yerine UAG'ye dönüşmüştür. Bu değişikliğin protein sentezine etkisini açıklayınız.","steps":[{"t":"AUG'nin görevi","a":"Başlangıç sağlar","d":"AUG kodonu translasyonun başladığı başlangıç kodonudur. Ribozom bu kodonu tanıyarak protein sentezini başlatır. Bu kodon olmadan sentez başlayamaz."},{"t":"UAG'ye dönüşüm","a":"Durdurma kodonu","d":"UAG bir durdurma kodonudur ve hiçbir aminoasit belirlemez. Başlangıç kodonu durdurma kodonuna dönüşürse ribozom başlatma sinyali bulamaz. Bu önemli bir değişikliktir."},{"t":"Sonuç","a":"Sentez başlamaz","d":"Başlangıç kodonu durdurma kodonuna dönüştüğü için ribozom doğru noktadan protein sentezini başlatamaz. Bu durumda işlevsel protein üretilemez. Mutasyon protein sentezini ciddi şekilde bozar."}],"ans":"Başlangıç kodonu durdurma kodonuna dönüştüğü için protein sentezi başlayamaz ve işlevsel protein oluşmaz"},{"q":"Bir mRNA'nın kodonları sırasıyla AUG, GCU, GCU, UAA şeklindedir. Bu mRNA'dan oluşan polipeptit hakkında aminoasit sayısı ve dizilimi açısından ne söylenebilir?","steps":[{"t":"Kodonları incele","a":"Dört kodon","d":"mRNA dört kodondan oluşur ve bunlar AUG, GCU, GCU, UAA'dır. Her kodon bir aminoaside karşılık gelebilir. Son kodon ise durdurma görevi taşıyabilir."},{"t":"Durdurma kodonu","a":"UAA durdurur","d":"Son kodon UAA bir durdurma kodonudur ve aminoasit belirlemez. Bu kodon protein sentezini sonlandırır. Bu nedenle polipeptide dahil edilmez."},{"t":"Aminoasit dizilimi","a":"3 aminoasit, ikisi aynı","d":"AUG, GCU ve GCU üç aminoasit kodlar; ikinci ve üçüncü kodon aynı olduğundan aynı aminoasit iki kez eklenir. Böylece 3 aminoasitlik bir polipeptit oluşur. Bu polipeptidin ikinci ve üçüncü aminoasitleri özdeştir."}],"ans":"3 aminoasitlik polipeptit oluşur; ikinci ve üçüncü aminoasitler aynıdır (UAA durdurur)"}]}},"kromozom":{"ilkokul":{"kolay":[{"q":"Vücudumuzdaki kalıtsal bilgiyi taşıyan, hücre çekirdeğinde bulunan iplik benzeri yapıların adı nedir?","steps":[{"t":"Kalıtım nerede saklanır?","a":"Çekirdekte","d":"Hücrelerimizin ortasında bulunan çekirdek, kalıtsal bilgilerimizi saklayan bölümdür. Saç rengimiz, göz rengimiz gibi özelliklerin bilgisi burada tutulur."},{"t":"İplik benzeri yapı","a":"Kromozom","d":"Çekirdek içinde kalıtsal bilgiyi taşıyan iplik benzeri yapılara kromozom denir. Kromozomlar üzerinde özelliklerimizi belirleyen bilgiler bulunur."}],"ans":"Kromozom"},{"q":"İnsan vücut hücrelerinde kaç tane kromozom bulunur?","steps":[{"t":"Kromozom sayısı","a":"Belirli bir sayı vardır","d":"Her canlı türünün hücrelerinde belirli sayıda kromozom bulunur. İnsanda bu sayı sabittir ve değişmez."},{"t":"İnsandaki sayı","a":"46 kromozom","d":"İnsanın vücut hücrelerinde toplam 46 tane kromozom bulunur. Bunların yarısı anneden, yarısı babadan gelir."}],"ans":"46 kromozom"},{"q":"Kromozomlar hücrenin hangi bölümünde bulunur?","steps":[{"t":"Hücrenin bölümleri","a":"Çekirdek önemli","d":"Hücrenin içinde çekirdek, sitoplazma ve zar gibi bölümler vardır. Bunlardan çekirdek kalıtsal bilgileri korur."},{"t":"Kromozomun yeri","a":"Çekirdek içinde","d":"Kromozomlar hücrenin çekirdeği içinde bulunur. Çekirdek bir kasa gibi kromozomları içinde saklar."}],"ans":"Çekirdekte"},{"q":"Çocukların kromozomlarının yarısı anneden gelirken diğer yarısı kimden gelir?","steps":[{"t":"Kromozomların gelişi","a":"İki kaynaktan","d":"Bir çocuğun kromozomları iki kişiden gelir. Bu yüzden çocuklar hem anneye hem babaya benzeyebilir."},{"t":"Diğer yarı","a":"Babadan","d":"Kromozomların yarısı anneden, diğer yarısı babadan gelir. Bu nedenle çocuk hem annesinden hem babasından özellikler taşır."}],"ans":"Babadan"},{"q":"Saç rengi, göz rengi gibi özelliklerimizin bilgisini taşıyan yapıların genel adı nedir?","steps":[{"t":"Özelliklerimiz","a":"Bilgi gerekir","d":"Saç rengi, göz rengi, boy gibi özelliklerimizin nasıl olacağı önceden bir yerde yazılıdır. Bu bilgilere kalıtsal bilgi denir."},{"t":"Bilgiyi taşıyan yapı","a":"Kromozom","d":"Bu kalıtsal bilgileri taşıyan yapılara kromozom denir. Kromozomlar çekirdekte bulunur ve özelliklerimizi belirler."}],"ans":"Kromozom"}],"zor":[{"q":"Bir hücrenin çekirdeğinde 46 kromozom vardır. Bu kromozomlardan kaç tanesi babadan gelmiştir?","steps":[{"t":"Kromozomların paylaşımı","a":"Yarı yarıya","d":"Kromozomlar anne ve babadan eşit olarak gelir. Yani toplam kromozomun yarısı anneden, yarısı babadan gelir."},{"t":"Babadan gelen sayı","a":"46 nın yarısı","d":"46 kromozomun yarısı 23 eder. Bu yüzden babadan gelen kromozom sayısı 23 tür."}],"ans":"23 kromozom"},{"q":"Kedinin vücut hücrelerinde 38 kromozom bulunur. İnsanın 46 kromozomu olduğuna göre hangi canlının kromozom sayısı daha fazladır?","steps":[{"t":"Sayıları karşılaştır","a":"İki sayı var","d":"Kedinin kromozom sayısı 38, insanın kromozom sayısı 46 dır. Bu iki sayıyı karşılaştırmamız gerekir."},{"t":"Hangisi büyük?","a":"46 daha büyük","d":"46 sayısı 38 sayısından büyüktür. Bu yüzden insanın kromozom sayısı kediden daha fazladır."}],"ans":"İnsan"},{"q":"Aynı türden olan iki insanın vücut hücrelerindeki kromozom sayıları neden birbirine eşittir?","steps":[{"t":"Tür kavramı","a":"Aynı tür","d":"İki insan da aynı canlı türüne aittir. Aynı türden canlılar birbirine benzer özellikler taşır."},{"t":"Tür ve kromozom","a":"Tür sabittir","d":"Aynı türün bütün bireylerinde kromozom sayısı aynıdır. Bu yüzden bütün insanların vücut hücrelerinde 46 kromozom bulunur."}],"ans":"Aynı türden oldukları için kromozom sayıları eşittir"},{"q":"Bir öğrenci, kromozomların gözle görülebileceğini düşünüyor. Kromozomları görebilmek için neye ihtiyacımız vardır?","steps":[{"t":"Kromozomun boyutu","a":"Çok küçük","d":"Kromozomlar gözle göremeyeceğimiz kadar küçük yapılardır. Çekirdeğin içinde bulunurlar ve çok ufaktırlar."},{"t":"Görmek için araç","a":"Mikroskop","d":"Çok küçük yapıları görebilmek için mikroskop kullanırız. Mikroskop küçük cisimleri büyüterek görmemizi sağlar."}],"ans":"Mikroskop"},{"q":"Bir çocuğun gözleri annesininki gibi kahverengi olmuştur. Bu durumun nedeni nedir?","steps":[{"t":"Özelliklerin aktarımı","a":"Kromozomlarla","d":"Anne ve babadan çocuğa kromozomlar aktarılır. Bu kromozomlar üzerinde göz rengi gibi özelliklerin bilgisi bulunur."},{"t":"Anneye benzeme","a":"Anneden gelen bilgi","d":"Çocuğun gözünün kahverengi olması, anneden gelen göz rengi bilgisi yüzündendir. Anneden alınan kromozomlar göz rengini belirlemiştir."}],"ans":"Göz rengi bilgisi anneden gelen kromozomlarla aktarılmıştır"}]},"ortaokul":{"kolay":[{"q":"DNA, gen ve kromozom yapılarını büyükten küçüğe doğru sıralayınız.","steps":[{"t":"Yapıları tanı","a":"Üç yapı var","d":"Kromozom çekirdekte bulunan büyük yapıdır. Gen kromozom üzerinde bir bölüm, DNA ise genleri oluşturan iplik yapısıdır."},{"t":"Büyüklük ilişkisi","a":"İç içe yapılar","d":"Kromozom genleri içerir, genler DNA parçalarından oluşur. Yani en büyük kromozom, en küçük yapı DNA dır."},{"t":"Sıralama","a":"Kromozom > gen > DNA","d":"Büyükten küçüğe sıralama kromozom, gen, DNA şeklindedir. Kromozom üzerinde genler, genlerin yapısında DNA bulunur."}],"ans":"Kromozom > Gen > DNA"},{"q":"Kromozom üzerinde bulunan ve bir özelliği belirleyen DNA parçasına ne ad verilir?","steps":[{"t":"Kromozomun içeriği","a":"DNA taşır","d":"Kromozomlar uzun DNA molekülünün sarılmasıyla oluşur. Bu DNA üzerinde belirli görevleri olan bölümler vardır."},{"t":"Özellik belirleyen parça","a":"Gen","d":"DNA üzerinde bir özelliği belirleyen anlamlı parçaya gen denir. Örneğin göz rengini belirleyen bir gen bulunur."}],"ans":"Gen"},{"q":"Hücre bölünmesi sırasında normalde ince iplik halinde olan kromatin yapısı ne hale gelir?","steps":[{"t":"Bölünme öncesi","a":"İnce iplik","d":"Hücre bölünmemişken kalıtsal madde ince ve uzun iplik halindedir. Bu yapıya kromatin denir."},{"t":"Bölünme sırasında","a":"Kısalır kalınlaşır","d":"Hücre bölüneceği zaman bu iplikler kısalıp kalınlaşarak yoğunlaşır. Böylece belirgin kromozomlar oluşur ve daha kolay görülür."}],"ans":"Kısalıp kalınlaşarak belirgin kromozoma dönüşür"},{"q":"Bir kromozomdaki iki kromatidi orta kısımda birbirine bağlayan yapının adı nedir?","steps":[{"t":"Kromozomun parçaları","a":"İki kromatit","d":"Bölünmeye hazırlanan bir kromozom iki özdeş koldan oluşur. Bu kollardan her birine kromatit denir."},{"t":"Birleştiren nokta","a":"Sentromer","d":"İki kromatidi orta bölgede birbirine bağlayan yapıya sentromer denir. Sentromer kromozomun boğum şeklindeki bölgesidir."}],"ans":"Sentromer"},{"q":"DNA molekülünün düzenli bir şekilde paketlenmesini sağlayan, etrafına DNA nın sarıldığı proteinlerin genel adı nedir?","steps":[{"t":"DNA çok uzun","a":"Paketlenmeli","d":"Hücredeki DNA çok uzundur ve küçük çekirdeğe sığması için düzenli paketlenmesi gerekir. Bunu tek başına yapamaz."},{"t":"Sarıldığı protein","a":"Histon","d":"DNA, histon adı verilen proteinlerin etrafına sarılarak paketlenir. Histonlar DNA nın düzenli kalmasını sağlar."}],"ans":"Histon proteinleri"}],"zor":[{"q":"Bir kromozom çok uzun bir DNA molekülü içerir. Bu kadar uzun DNA, küçük çekirdeğe nasıl sığar?","steps":[{"t":"Sorun: yer az","a":"DNA uzun","d":"Bir hücredeki DNA açılırsa metrelerce uzunluğa ulaşır. Ancak çekirdek mikroskobik boyuttadır, bu yüzden DNA nın sıkıştırılması gerekir."},{"t":"Çözüm: protein sarımı","a":"Histona sarılma","d":"DNA, histon adlı proteinlerin etrafına sarılarak makaraya sarılan ip gibi paketlenir. Bu sayede uzun DNA çok az yer kaplar."},{"t":"Sonuç","a":"Sığar","d":"DNA nın histonlara sarılması ve bunların üst üste katlanmasıyla DNA küçük çekirdeğe sığar. Bu paketlenme kromozomu oluşturur."}],"ans":"DNA histon proteinlerine sarılıp katlanarak paketlendiği için çekirdeğe sığar"},{"q":"Kromozom sayısı 2 katına çıkmadan önce DNA da bir olay gerçekleşir. Bölünme öncesi kromatit sayısının iki katına çıkmasının nedeni nedir?","steps":[{"t":"Bölünme hazırlığı","a":"Kopya gerekir","d":"Hücre bölünmeden önce kalıtsal maddesini iki katına çıkarır. Çünkü oluşacak iki hücreye de tam bilgi gitmelidir."},{"t":"DNA kendini eşler","a":"Replikasyon","d":"DNA kendini eşleyerek özdeş bir kopyasını oluşturur. Böylece her özelliğin iki kopyası hazır olur."},{"t":"İki kromatit","a":"Özdeş kollar","d":"Eşlenen DNA sayesinde her kromozom iki özdeş kromatitten oluşur. Bu iki kromatit sentromerle bağlıdır ve bölünmede ayrılacaktır."}],"ans":"DNA kendini eşlediği (replikasyon) için her kromozom iki özdeş kromatit içerir"},{"q":"Bir öğrenci kromatin ile kromozomun farklı maddeler olduğunu düşünüyor. Bu düşünce neden yanlıştır?","steps":[{"t":"Aynı madde","a":"Tek yapı","d":"Kromatin ve kromozom aslında aynı kalıtsal maddenin farklı görünümleridir. İkisi de DNA ve histon proteinlerinden oluşur."},{"t":"Fark görünümde","a":"Yoğunlaşma derecesi","d":"Hücre bölünmüyorken madde ince iplik halinde olup kromatin denir. Bölünme sırasında kısalıp kalınlaşınca kromozom adını alır."},{"t":"Sonuç","a":"Aynı şeyin halleri","d":"Yani kromatin ve kromozom farklı maddeler değildir. Aynı yapının açık ve yoğunlaşmış iki halidir."}],"ans":"Kromatin ve kromozom aynı maddenin farklı yoğunlaşma halleridir, ayrı madde değildir"},{"q":"Bir canlının vücut hücresinde 12 kromozom vardır. Bu canlının üreme hücresinde (gametinde) kaç kromozom bulunur?","steps":[{"t":"Vücut ve üreme hücresi","a":"Farklı sayı","d":"Vücut hücreleri tam kromozom sayısına sahiptir. Üreme hücreleri ise bu sayının yarısını taşır."},{"t":"Neden yarısı?","a":"Birleşme için","d":"İki üreme hücresi birleştiğinde yeni canlının tam sayıya ulaşması gerekir. Bu yüzden her gamet kromozom sayısının yarısını taşır."},{"t":"Hesap","a":"12 nin yarısı","d":"12 kromozomun yarısı 6 eder. Bu yüzden bu canlının üreme hücresinde 6 kromozom bulunur."}],"ans":"6 kromozom"},{"q":"Saç rengini belirleyen genin DNA üzerinde, kromozom üzerinde ve hücredeki yeri nasıl açıklanır? Bu yapıların ilişkisini sıralayınız.","steps":[{"t":"En küçük: gen","a":"DNA parçası","d":"Saç rengini belirleyen gen, DNA molekülü üzerinde bir bölümdür. Gen, anlamlı bir DNA parçasıdır."},{"t":"Genler DNA da","a":"DNA genleri taşır","d":"Çok sayıda gen bir araya gelerek DNA molekülünü oluşturur. DNA histon proteinlerine sarılır."},{"t":"DNA kromozomda","a":"Kromozom çekirdekte","d":"Paketlenen DNA kromozomu oluşturur ve kromozomlar çekirdekte bulunur. Böylece sıralama gen, DNA, kromozom, çekirdek şeklindedir."}],"ans":"Gen DNA üzerindedir, DNA kromozomu oluşturur, kromozomlar çekirdektedir"}]},"lise":{"kolay":[{"q":"Ökaryot hücrede DNA nın etrafına sarıldığı, paketlenmesini sağlayan bazik proteinlerin adı nedir ve bunların oluşturduğu temel paketlenme birimine ne denir?","steps":[{"t":"Paketleyici proteinler","a":"Histonlar","d":"DNA, pozitif yüklü bazik proteinler olan histonların etrafına sarılır. Histonların pozitif yükü, DNA nın negatif yüklü fosfat grubuyla etkileşir."},{"t":"Temel paketlenme birimi","a":"Nükleozom","d":"DNA nın histon oktameri etrafına yaklaşık iki tur sarılmasıyla nükleozom oluşur. Nükleozom kromatinin en temel paketlenme birimidir."}],"ans":"Histon proteinleri; nükleozom"},{"q":"Bir nükleozom yapısında kaç histon proteininden oluşan bir çekirdek bulunur?","steps":[{"t":"Nükleozom çekirdeği","a":"Histon oktameri","d":"Nükleozomun merkezinde histon proteinlerinden oluşan bir çekirdek vardır. Bu çekirdeğin etrafına DNA sarılır."},{"t":"Histon sayısı","a":"Sekiz histon","d":"Bu çekirdek dört çeşit histonun ikişer kopyasından, yani toplam sekiz histon proteininden oluşur. Bu yapıya histon oktameri denir."}],"ans":"Sekiz histon (histon oktameri)"},{"q":"Nükleozomların art arda dizilmesiyle oluşan, mikroskopta boncuk dizisi görünümü veren ipliksi yapının adı nedir?","steps":[{"t":"Nükleozomların dizilişi","a":"Art arda","d":"Çok sayıda nükleozom bir DNA ipliği üzerinde art arda dizilir. Bu diziliş ince bir iplik görünümü oluşturur."},{"t":"Oluşan yapı","a":"Kromatin ipliği","d":"Boncuk dizisi görünümündeki bu yapıya kromatin ipliği denir. Kromatin, DNA ve histon proteinlerinin birlikte oluşturduğu yapıdır."}],"ans":"Kromatin ipliği"},{"q":"Hücre bölünmesi sırasında kromatin ipliği kromozoma dönüşürken hangi fiziksel değişim gerçekleşir?","steps":[{"t":"Bölünme ihtiyacı","a":"Düzenli ayrım","d":"Hücre bölünürken kalıtsal maddenin iki hücreye düzgün dağılması gerekir. Uzun ince iplik halinde dağıtım zordur."},{"t":"Yoğunlaşma","a":"Kısalıp kalınlaşma","d":"Kromatin ipliği daha fazla katlanıp sarmalanarak kısalır ve kalınlaşır. Bu yoğunlaşma sonucu belirgin kromozomlar oluşur."}],"ans":"Kromatin kısalıp kalınlaşarak (yoğunlaşarak) kromozoma dönüşür"},{"q":"Eşlenmiş bir kromozomda bulunan iki özdeş kola ne ad verilir ve bunları birbirine bağlayan bölge nedir?","steps":[{"t":"Eşlenmiş kromozom","a":"İki kol","d":"DNA replikasyonundan sonra her kromozom iki özdeş koldan oluşur. Bu kollar aynı genetik bilgiyi taşır."},{"t":"Kollar ve bağlantı","a":"Kardeş kromatit ve sentromer","d":"Bu özdeş kolların her birine kardeş kromatit denir. İki kardeş kromatidi birbirine bağlayan boğum bölgesine sentromer denir."}],"ans":"Kardeş kromatitler; sentromer"},{"q":"Kromozom, gen ve nükleotit yapılarını büyükten küçüğe doğru sıralayınız.","steps":[{"t":"Yapıların tanımı","a":"Üç birim","d":"Kromozom paketlenmiş DNA dır, gen anlamlı bir DNA parçasıdır, nükleotit ise DNA nın yapı birimidir. Bunlar farklı büyüklüklerdedir."},{"t":"İç içe ilişki","a":"Kromozom genleri içerir","d":"Bir kromozom çok sayıda gen taşır, her gen ise çok sayıda nükleotitten oluşur. Yani en büyük kromozom, en küçük nükleotittir."},{"t":"Sıralama","a":"Kromozom > gen > nükleotit","d":"Büyükten küçüğe sıralama kromozom, gen, nükleotit şeklindedir. Kromozom genleri, genler nükleotitleri içerir."}],"ans":"Kromozom > Gen > Nükleotit"},{"q":"DNA, gen, kromozom ve nükleotit yapılarının kalıtsal bilgi açısından ilişkisi nasıldır?","steps":[{"t":"En küçük birim","a":"Nükleotit","d":"DNA nın yapı birimi nükleotittir. Nükleotitlerin belirli bir sırada dizilmesi genetik bilgiyi oluşturur."},{"t":"Gen ve DNA","a":"Anlamlı diziler","d":"Belirli bir özelliği şifreleyen anlamlı nükleotit dizisine gen denir. Çok sayıda gen DNA molekülünü oluşturur."},{"t":"Kromozom","a":"Paketlenmiş DNA","d":"DNA histonlara sarılıp paketlenince kromozomu oluşturur. Yani kromozom genleri, genler DNA dizilerini içerir."}],"ans":"Nükleotitler geni, genler DNA yı, paketlenmiş DNA da kromozomu oluşturur"},{"q":"Homolog kromozom kavramı ne anlama gelir?","steps":[{"t":"Kromozom çiftleri","a":"İkili gelir","d":"Vücut hücrelerinde kromozomlar çiftler halinde bulunur. Her çiftin biri anneden, biri babadan gelir."},{"t":"Homolog tanımı","a":"Benzer çiftler","d":"Aynı özellikleri belirleyen genleri taşıyan, biri anneden biri babadan gelen kromozom çiftine homolog kromozomlar denir. Şekil ve büyüklükleri benzerdir."}],"ans":"Biri anneden biri babadan gelen, aynı genleri taşıyan benzer kromozom çiftleri"},{"q":"Kromatinin yoğun şekilde paketlenmiş ve genellikle pasif olan bölümüne ne ad verilir?","steps":[{"t":"Kromatin çeşitleri","a":"İki tip","d":"Kromatin yoğunluğuna göre iki şekilde bulunur. Bir kısmı sıkı, bir kısmı gevşek paketlenir."},{"t":"Yoğun bölge","a":"Heterokromatin","d":"Sıkıca paketlenmiş, koyu görünen ve genellikle gen ifadesinin pasif olduğu bölgeye heterokromatin denir. Gevşek ve aktif bölgeye ise ökromatin denir."}],"ans":"Heterokromatin"},{"q":"İnsanda vücut hücrelerinde 46, üreme hücrelerinde 23 kromozom bulunmasının nedeni nedir?","steps":[{"t":"İki hücre tipi","a":"Farklı sayı","d":"Vücut hücreleri 2n yani diploit, üreme hücreleri n yani haploit kromozom taşır. Üreme hücresindeki sayı yarımdır."},{"t":"Döllenme","a":"Sayı korunur","d":"İki üreme hücresi döllenmede birleşir. 23 ve 23 birleşince 46 kromozomlu zigot oluşur, böylece tür kromozom sayısı korunur."}],"ans":"Üreme hücreleri yarı sayıda kromozom taşır ki döllenmede tür sayısı (46) korunsun"},{"q":"Sentromerin hücre bölünmesindeki temel görevi nedir?","steps":[{"t":"Sentromerin yeri","a":"Boğum bölgesi","d":"Sentromer, kardeş kromatitleri birbirine bağlayan boğum şeklindeki bölgedir. Kromozomun belirli bir bölgesinde bulunur."},{"t":"Bölünmedeki görev","a":"İğ ipliği bağlanması","d":"Bölünme sırasında iğ iplikleri sentromer bölgesine tutunur. Bu iplikler kardeş kromatitleri kutuplara çekerek eşit dağılımı sağlar."}],"ans":"İğ ipliklerinin tutunmasını ve kromatitlerin kutuplara eşit çekilmesini sağlar"},{"q":"Bir DNA molekülü hücrede tek başına değil de histonlarla birlikte bulunur. Histonların temel kimyasal özelliği bu ilişkiyi nasıl açıklar?","steps":[{"t":"DNA nın yükü","a":"Negatif","d":"DNA molekülü, üzerindeki fosfat grupları nedeniyle negatif yüklüdür. Bu yük boyunca dağılmıştır."},{"t":"Histonun yükü","a":"Pozitif (bazik)","d":"Histon proteinleri bazik yapıda olup pozitif yüklüdür. Zıt yükler birbirini çeker, böylece DNA histonlara sıkıca sarılır."}],"ans":"Pozitif yüklü bazik histonlar negatif yüklü DNA yı çekerek paketlenmesini sağlar"},{"q":"Kromozomların sentromer konumuna göre adlandırılması yapılır. Sentromeri tam ortada olan kromozoma ne ad verilir?","steps":[{"t":"Sentromer konumu","a":"Değişebilir","d":"Kromozomlarda sentromer her zaman tam ortada olmaz. Konumuna göre kromozomlar farklı isimler alır."},{"t":"Ortadaki sentromer","a":"Metasentrik","d":"Sentromeri tam ortada bulunan, iki kolu eşit uzunlukta olan kromozoma metasentrik kromozom denir. Bu durumda kromozom V harfine benzer."}],"ans":"Metasentrik kromozom"},{"q":"Prokaryot hücrelerin kromozom yapısı ökaryotlardan hangi yönüyle temel olarak farklıdır?","steps":[{"t":"Prokaryot DNA","a":"Halkasal","d":"Bakteri gibi prokaryotlarda DNA genellikle tek ve halkasal (dairesel) yapıdadır. Sitoplazmada serbest bulunur, çekirdek zarı yoktur."},{"t":"Histon farkı","a":"Histon yok/farklı","d":"Prokaryotlarda tipik ökaryot histonları bulunmaz veya farklı paketleyici proteinler kullanılır. Ökaryotta ise doğrusal DNA histonlara sarılarak paketlenir."}],"ans":"Prokaryot DNA sı halkasal ve histonsuzdur, ökaryot DNA sı doğrusal ve histonlarla paketlidir"},{"q":"Replikasyondan sonra bir kromozom iki kardeş kromatit içerir. Bu iki kromatidin genetik içeriği için ne söylenebilir?","steps":[{"t":"Replikasyonun amacı","a":"Birebir kopya","d":"DNA replikasyonu, mevcut DNA nın birebir aynısını üretir. Bu sayede genetik bilgi değişmeden çoğaltılır."},{"t":"Kromatitlerin içeriği","a":"Özdeş","d":"Replikasyon sonucu oluşan iki kardeş kromatit aynı genleri ve aynı DNA dizisini taşır. Yani genetik içerikleri birbirinin tıpatıp aynısıdır."}],"ans":"İki kardeş kromatit genetik olarak birbirinin özdeşidir (aynı DNA dizisini taşır)"}],"zor":[{"q":"Bir insan hücresindeki DNA açıldığında yaklaşık 2 metre uzunluğa ulaşır. Bu DNA, çapı mikrometre düzeyindeki çekirdeğe nasıl sığar? Paketlenme aşamalarını sıralayarak açıklayınız.","steps":[{"t":"Birinci düzey","a":"Nükleozom","d":"DNA önce histon oktameri etrafına yaklaşık iki tur sarılarak nükleozomları oluşturur. Bu, paketlenmenin ilk ve temel düzeyidir."},{"t":"İkinci düzey","a":"30 nm iplik","d":"Nükleozomlar birbirine yaklaşıp sarmal şeklinde katlanarak daha kalın bir kromatin ipliği oluşturur. Böylece DNA daha sıkı paketlenir."},{"t":"Üst düzeyler","a":"İlmek ve katlanma","d":"Bu iplik protein iskeletine ilmekler halinde tutunur ve daha da katlanır. Bölünme sırasında bu yapı en yoğun haline gelerek kromozomu oluşturur."},{"t":"Sonuç","a":"Sığar","d":"Çok aşamalı paketlenme sayesinde 2 metrelik DNA mikroskobik çekirdeğe sığar. Her aşama DNA yı binlerce kat kısaltır."}],"ans":"DNA nükleozom, 30 nm iplik, ilmekli yapı ve katlanma aşamalarıyla paketlenerek çekirdeğe sığar"},{"q":"Bir öğrenci, replikasyon olmadan hücrenin mitozla bölünebileceğini iddia ediyor. Bu iddianın neden hatalı olduğunu kromozom yapısı üzerinden açıklayınız.","steps":[{"t":"Mitozun amacı","a":"Özdeş hücreler","d":"Mitoz sonucu oluşan iki hücre, ana hücreyle aynı kromozom sayısına ve genetik bilgiye sahip olmalıdır. Yani her hücre tam bilgi almalıdır."},{"t":"Replikasyonun rolü","a":"İki kromatit","d":"Bölünme öncesi DNA replikasyonu olmazsa kromozomlar tek kromatitli kalır. Bu durumda ayrılacak ikinci bir özdeş kopya bulunmaz."},{"t":"Replikasyonsuz sonuç","a":"Eksik bilgi","d":"Replikasyon olmadan bölünme yapılırsa kromozomlar iki hücreye eksik dağılır. Hücreler tam ve eşit genetik bilgi alamaz."},{"t":"Çürütme","a":"Replikasyon zorunlu","d":"Bu yüzden mitozdan önce replikasyon zorunludur. Replikasyon, kardeş kromatitleri oluşturup eşit dağılımı mümkün kılar, dolayısıyla iddia hatalıdır."}],"ans":"Replikasyon olmazsa kardeş kromatit oluşmaz ve iki hücreye eşit özdeş bilgi gidemez, bu yüzden iddia hatalıdır"},{"q":"Heterokromatin ve ökromatin bölgelerinde gen ifadesinin farklı olmasının nedeni paketlenme yoğunluğuyla nasıl ilişkilendirilir?","steps":[{"t":"İki kromatin tipi","a":"Yoğunluk farkı","d":"Ökromatin gevşek paketlenmiş, heterokromatin ise sıkıca paketlenmiş kromatindir. Bu yapısal fark işlevsel sonuçlar doğurur."},{"t":"Erişilebilirlik","a":"Enzim ulaşımı","d":"Gen ifadesi için RNA polimeraz ve transkripsiyon faktörlerinin DNA ya ulaşması gerekir. Gevşek ökromatinde DNA erişilebilirken, sıkı heterokromatinde DNA bu proteinlere kapalıdır."},{"t":"Sonuç","a":"Aktif ve pasif","d":"Bu yüzden ökromatin bölgelerinde genler aktif olarak ifade edilir, heterokromatinde ise genellikle ifade edilmez. Paketlenme yoğunluğu gen ifadesini doğrudan düzenler."}],"ans":"Gevşek ökromatinde DNA enzimlere açık olduğundan genler aktif, sıkı heterokromatinde kapalı olduğundan pasiftir"},{"q":"Bir canlının vücut hücresinde 2n=16 kromozom vardır. Bu hücre interfaz S evresinden geçtikten sonra hücredeki kromatit sayısı kaç olur ve neden?","steps":[{"t":"Başlangıç durumu","a":"16 kromozom","d":"S evresi öncesinde hücrede 16 kromozom bulunur ve her kromozom tek kromatitlidir. Yani başlangıçta 16 kromatit vardır."},{"t":"S evresi","a":"DNA eşlenir","d":"S evresinde DNA replikasyonu gerçekleşir ve her kromozomun DNA sı iki katına çıkar. Böylece her kromozom iki kardeş kromatit içerir."},{"t":"Hesap","a":"16 × 2","d":"Kromozom sayısı hâlâ 16 dır çünkü kardeş kromatitler sentromerle bağlıdır. Ancak kromatit sayısı 16 × 2 = 32 olur."}],"ans":"32 kromatit, çünkü S evresinde DNA eşlenerek her kromozom iki kardeş kromatitli olur"},{"q":"Down sendromu (21. kromozomun üç kopyası), kromozom dağılımındaki bir hatayla ilişkilidir. Bu durumun kromozom davranışı açısından nasıl oluştuğunu açıklayınız.","steps":[{"t":"Normal dağılım","a":"Eşit ayrılma","d":"Üreme hücreleri oluşurken homolog kromozomlar ve kardeş kromatitler eşit olarak ayrılır. Böylece her gamet doğru sayıda kromozom alır."},{"t":"Ayrılmama","a":"Hatalı dağılım","d":"Bazen kromozomlar düzgün ayrılmaz, buna ayrılmama denir. 21. kromozom çifti ayrılmazsa bir gamete bu kromozomdan iki tane gider."},{"t":"Döllenme sonrası","a":"Üç kopya","d":"Bu gamet normal bir gametle döllenince 21. kromozomdan üç kopya bulunan zigot oluşur. Bu fazladan kromozom Down sendromuna yol açar."}],"ans":"Üreme hücresi oluşurken 21. kromozomun ayrılmaması sonucu zigotta bu kromozomdan üç kopya bulunur"},{"q":"Eşey kromozomları ile vücut (otozom) kromozomları arasındaki fark nedir ve insanda cinsiyet bunlarla nasıl belirlenir?","steps":[{"t":"İki kromozom grubu","a":"Otozom ve eşey","d":"İnsanda 46 kromozomun 44 ü otozom, 2 si eşey kromozomudur. Otozomlar vücut özelliklerini, eşey kromozomları cinsiyeti belirler."},{"t":"Eşey kromozomları","a":"X ve Y","d":"Eşey kromozomları X ve Y olarak adlandırılır. Kadında XX, erkekte XY kromozomları bulunur."},{"t":"Cinsiyet belirleme","a":"Spermin getirdiği","d":"Yumurta her zaman X taşırken, sperm X veya Y taşıyabilir. Spermin getirdiği kromozom X ise kız (XX), Y ise erkek (XY) birey oluşur."}],"ans":"44 otozom vücut özelliklerini, 2 eşey kromozomu (XX kadın, XY erkek) cinsiyeti belirler; cinsiyeti spermin taşıdığı kromozom belirler"},{"q":"Karyotip analizinde kromozomların boy, sentromer konumu ve bantlanma deseni kullanılır. Bu analiz neden kromozom anormalliklerini tespit edebilir?","steps":[{"t":"Karyotip nedir","a":"Kromozom haritası","d":"Karyotip, bir hücredeki kromozomların büyüklük ve şekillerine göre çiftler halinde düzenlenmiş görüntüsüdür. Bölünmedeki yoğunlaşmış kromozomlardan hazırlanır."},{"t":"Ayırt edici özellikler","a":"Boy, sentromer, bant","d":"Her kromozom çifti kendine özgü uzunluk, sentromer konumu ve bantlanma desenine sahiptir. Bu özellikler kromozomların tek tek tanınmasını sağlar."},{"t":"Anormallik tespiti","a":"Sapma görünür","d":"Normal sayı veya yapıdan sapma karyotipte fark edilir. Örneğin fazladan bir kromozom veya kırık bir parça karyotip incelemesiyle görülebilir."}],"ans":"Her kromozomun boy, sentromer ve bant deseni özgün olduğundan sayısal/yapısal sapmalar karyotipte görünür hale gelir"},{"q":"Bir hücrede n=4 olduğu bilinmektedir. Bu canlının vücut hücresindeki kromozom sayısını, homolog kromozom çifti sayısını ve mitoz metafazındaki kromatit sayısını bulunuz.","steps":[{"t":"Vücut hücresi sayısı","a":"2n","d":"n=4 haploit sayıyı gösterir, vücut hücresi diploit yani 2n dir. Bu yüzden vücut hücresinde 2 × 4 = 8 kromozom bulunur."},{"t":"Homolog çift","a":"4 çift","d":"Diploit hücrede kromozomlar çiftler halindedir ve çift sayısı n ye eşittir. Yani 4 homolog kromozom çifti vardır."},{"t":"Metafaz kromatiti","a":"8 × 2","d":"Mitoz metafazında her kromozom replike olmuş ve iki kardeş kromatit taşır. 8 kromozom × 2 = 16 kromatit bulunur."}],"ans":"Vücut hücresi 8 kromozom, 4 homolog çift, mitoz metafazında 16 kromatit"},{"q":"Histon proteinlerinin kuyruk bölgelerine kimyasal gruplar (asetil, metil) eklenmesi gen ifadesini etkiler. Bu olay paketlenme ve gen ifadesi ilişkisini nasıl açıklar?","steps":[{"t":"Histon kuyrukları","a":"Modifiye edilebilir","d":"Histonların DNA dışına uzanan kuyruk bölgelerine asetil veya metil gibi kimyasal gruplar eklenebilir. Bu değişikliklere histon modifikasyonu denir."},{"t":"Paketlenmeye etki","a":"Gevşetme/sıkılaştırma","d":"Örneğin asetil grubu eklenmesi histonun pozitif yükünü azaltır ve DNA yı gevşetir. Böylece kromatin ökromatin haline gelir ve DNA erişilebilir olur."},{"t":"Gen ifadesine etki","a":"Aktif/pasif","d":"Gevşeyen bölgelerde genler aktif şekilde ifade edilirken, sıkılaşan bölgelerde ifade baskılanır. Böylece histon modifikasyonu DNA dizisini değiştirmeden gen ifadesini düzenler."}],"ans":"Histon modifikasyonları kromatini gevşetip sıkılaştırarak DNA erişilebilirliğini ve dolayısıyla gen ifadesini düzenler"},{"q":"Kromozomun uçlarında telomer denilen tekrar dizileri bulunur. Telomerlerin kromozom yapısı açısından görevi nedir?","steps":[{"t":"Telomerin yeri","a":"Kromozom uçları","d":"Telomerler, doğrusal kromozomların uçlarında bulunan tekrarlayan DNA dizileridir. Protein kodlamayan koruyucu bölgelerdir."},{"t":"Koruma görevi","a":"Uçları korur","d":"Telomerler kromozom uçlarının yıpranmasını ve birbirine yapışmasını engeller. Ayrıca hücreye uçların kırık DNA olmadığını bildirir."},{"t":"Replikasyonla ilişki","a":"Kısalma tamponu","d":"Her replikasyonda kromozom uçları biraz kısalır ve telomerler bu kayıpta tampon görevi görür. Böylece önemli genler korunmuş olur."}],"ans":"Telomerler kromozom uçlarını yıpranma ve yapışmadan korur, replikasyondaki kısalmaya tampon oluşturur"},{"q":"Mitoz ve mayoz bölünme sonunda oluşan hücrelerin kromozom sayıları farklıdır. Bir hücre 2n=10 ise her iki bölünme sonunda oluşan hücrelerin kromozom sayısını ve farkın nedenini açıklayınız.","steps":[{"t":"Mitoz sonucu","a":"2n korunur","d":"Mitozda ana hücre bir kez bölünür ve oluşan iki hücre ana hücreyle aynı kromozom sayısına sahip olur. 2n=10 olduğundan her hücre 10 kromozom taşır."},{"t":"Mayoz sonucu","a":"n e iner","d":"Mayozda hücre iki kez bölünürken DNA bir kez eşlenir, bu yüzden kromozom sayısı yarıya iner. Oluşan dört hücrede 10 nun yarısı olan 5 kromozom bulunur."},{"t":"Farkın nedeni","a":"Homolog ayrılması","d":"Mayozun birinci bölünmesinde homolog kromozomlar ayrılır, bu yüzden sayı yarıya düşer. Bu üreme hücrelerinin haploit olmasını ve tür sayısının korunmasını sağlar."}],"ans":"Mitozda 10, mayozda 5 kromozomlu hücre oluşur; mayozda homolog kromozomların ayrılmasıyla sayı yarıya iner"},{"q":"DNA-gen-kromozom büyüklük ilişkisinde bir öğrenci geni kromozomdan büyük sanıyor. Bu yanılgıyı yapısal hiyerarşi üzerinden düzeltiniz.","steps":[{"t":"Yanılgının kaynağı","a":"İsim karışıklığı","d":"Öğrenci, gen ve kromozom terimlerini önem sırasına göre düşünüp boyutlarını karıştırmış olabilir. Oysa bu yapılar arasında belirli bir büyüklük hiyerarşisi vardır."},{"t":"Doğru hiyerarşi","a":"İç içe yapı","d":"Bir kromozom tek bir uzun DNA molekülünden oluşur ve bu DNA üzerinde yüzlerce ya da binlerce gen bulunur. Yani gen, kromozomun küçük bir parçasıdır."},{"t":"Boyut karşılaştırması","a":"Kromozom en büyük","d":"Büyüklük sırası kromozom, DNA, gen, nükleotit şeklindedir. Dolayısıyla gen kromozomdan çok daha küçüktür, öğrencinin düşüncesi yanlıştır."}],"ans":"Gen, kromozom üzerindeki bir DNA parçasıdır; kromozom binlerce gen taşır, bu yüzden gen kromozomdan küçüktür"},{"q":"Poliploidi (kromozom takımının katlanması) bitkilerde sıkça görülür ve genellikle daha iri bireyler oluşturur. Bu durumun kromozom sayısı açısından nasıl oluştuğunu açıklayınız.","steps":[{"t":"Normal takım","a":"2n diploit","d":"Çoğu canlı diploittir, yani her kromozomdan iki takım taşır (2n). Bu takımlar üreme sırasında düzgün ayrılır."},{"t":"Katlanma","a":"Ayrılmama","d":"Hücre bölünmesinde tüm kromozomlar ayrılmazsa kromozom takımı katlanır. Böylece 3n, 4n gibi fazla takımlı hücreler oluşur."},{"t":"Sonuç","a":"İri bireyler","d":"Fazla kromozom takımı daha fazla gen ve genellikle daha büyük hücreler demektir. Bu yüzden poliploit bitkiler çoğunlukla daha iri ve verimli olur."}],"ans":"Kromozomların ayrılmaması sonucu takım sayısı katlanır (3n, 4n) ve genellikle daha iri bireyler oluşur"},{"q":"Bir kromozomda meydana gelen yapısal bozulmalardan biri olan delesyon nedir ve hücre üzerindeki olası etkisi nasıl açıklanır?","steps":[{"t":"Yapısal mutasyon","a":"Kromozom değişimi","d":"Kromozomun yapısında kırılma ve yeniden düzenlenme sonucu çeşitli bozukluklar oluşabilir. Bunlardan biri parça kaybıdır."},{"t":"Delesyon tanımı","a":"Parça kaybı","d":"Delesyon, kromozomun bir parçasının kopup kaybolmasıdır. Bu parçada bulunan genler de hücreden eksilir."},{"t":"Olası etki","a":"Gen eksikliği","d":"Kaybolan parçadaki genlerin proteinleri üretilemez. Bu durum, kaybedilen genlerin önemine göre hücrede işlev bozukluğuna veya kalıtsal hastalıklara yol açabilir."}],"ans":"Delesyon kromozomdan bir parçanın kopmasıdır; o bölgedeki genler kaybolduğundan işlev bozukluğu veya hastalık görülebilir"},{"q":"İnterfazda kromatin gevşek, bölünme sırasında ise yoğunlaşmış halde bulunur. Bu iki halin hücre için işlevsel avantajları nelerdir?","steps":[{"t":"İnterfaz hali","a":"Gevşek kromatin","d":"İnterfazda kromatin gevşek olduğu için DNA, transkripsiyon ve replikasyon enzimlerine açıktır. Bu sayede gen ifadesi ve DNA eşlenmesi gerçekleşebilir."},{"t":"Bölünme hali","a":"Yoğun kromozom","d":"Bölünme sırasında kromatin yoğunlaşıp kromozom haline gelir. Kompakt yapı, kromozomların dolaşmadan ve kopmadan hareket etmesini sağlar."},{"t":"İşlevsel avantaj","a":"Hem ifade hem taşıma","d":"Gevşek hal aktif moleküler işlemleri, yoğun hal ise güvenli ve eşit kromozom dağıtımını mümkün kılar. Hücre ihtiyaca göre iki hal arasında geçiş yapar."}],"ans":"Gevşek hal gen ifadesi ve replikasyona izin verir, yoğun hal kromozomların güvenli ve eşit taşınmasını sağlar"}]}},"genetikKod":{"ilkokul":{"kolay":[{"q":"Saç rengimiz, göz rengimiz gibi özelliklerimizin nasıl olacağını belirleyen, anne ve babadan bize geçen kalıtsal bilgi birimine ne ad verilir?","steps":[{"t":"Özelliklerimizin kaynağı","a":"Kalıtsal bilgi","d":"Saç ve göz rengi gibi özelliklerimiz anne ve babamızdan bize geçer. Bu geçiş bir bilgi aktarımıyla olur."},{"t":"Bilgi birimi","a":"Gen","d":"Bu kalıtsal bilgiyi taşıyan birime gen denir. Her gen bir özelliğin nasıl olacağını belirler."}],"ans":"Gen"},{"q":"Genler hangi büyük yapının üzerinde bulunur?","steps":[{"t":"Genin yeri","a":"Bir yapı üzerinde","d":"Genler kendi başına havada durmaz, daha büyük bir yapının üzerinde sıralanır. Bu yapı çekirdekte bulunur."},{"t":"Üzerinde olduğu yapı","a":"Kromozom","d":"Genler kromozomların üzerinde sıralı şekilde bulunur. Bir kromozom üzerinde birçok gen yer alır."}],"ans":"Kromozom"},{"q":"Vücudumuzun yapı taşı olan ve genlerin yapılmasını şifrelediği maddelere ne ad verilir?","steps":[{"t":"Vücut yapı taşı","a":"Önemli madde","d":"Vücudumuzun büyük kısmı belirli yapı taşı maddelerden oluşur. Bu maddeler kasları, saçı ve birçok bölümü oluşturur."},{"t":"Genin şifrelediği","a":"Protein","d":"Genler, protein adı verilen bu yapı taşlarının üretimini şifreler. Yani genler vücudun proteinlerini belirler."}],"ans":"Protein"},{"q":"Bir gen bozulursa o gene bağlı olan özellikte ne olabilir?","steps":[{"t":"Genin görevi","a":"Özellik belirler","d":"Her gen bir özelliğin nasıl olacağını belirler. Gen sağlamsa özellik düzgün ortaya çıkar."},{"t":"Bozulma durumu","a":"Özellik değişir","d":"Gen bozulursa belirlediği özellik değişebilir veya doğru oluşmayabilir. Bu yüzden genler çok önemlidir."}],"ans":"Özellik değişebilir veya düzgün oluşmayabilir"},{"q":"İkizler dışında her insanın genlerinin birbirinden biraz farklı olması bize neyi gösterir?","steps":[{"t":"Genler ve özellikler","a":"Genler farklı","d":"Her insanın genleri birbirinden biraz farklıdır. Genler özelliklerimizi belirlediği için bu farklar bize yansır."},{"t":"Sonuç","a":"Herkes farklı","d":"Farklı genler yüzünden her insan birbirinden farklı görünür. Bu yüzden herkesin kendine özgü özellikleri vardır."}],"ans":"Her insanın birbirinden farklı (özgün) olduğunu gösterir"}],"zor":[{"q":"Bir kromozom üzerinde birçok gen bulunur. Buna göre gen mi yoksa kromozom mu daha büyük bir yapıdır?","steps":[{"t":"İlişkiyi düşün","a":"Gen kromozomda","d":"Genler kromozomun üzerinde sıralı şekilde bulunur. Bir kromozom üzerinde çok sayıda gen yer alır."},{"t":"Büyüklük","a":"Kromozom büyük","d":"Üzerinde birçok gen taşıyan kromozom, tek bir genden daha büyüktür. Yani kromozom genden daha büyük bir yapıdır."}],"ans":"Kromozom daha büyüktür"},{"q":"Bir bitkinin çiçek renginin kırmızı olması ile o renge ait gen arasında nasıl bir ilişki vardır?","steps":[{"t":"Genin görevi","a":"Şifre taşır","d":"Genler bir özelliğin nasıl olacağına dair şifreyi taşır. Çiçek rengi de bir gen tarafından belirlenir."},{"t":"Kırmızı renk","a":"Gen belirler","d":"Bitkide kırmızı renk geni bulunduğu için çiçek kırmızı olmuştur. Yani gen, çiçeğin rengini belirleyen bilgiyi taşır."}],"ans":"Çiçeğin kırmızı rengi, o renge ait gen tarafından belirlenir"},{"q":"Bir öğrenci, genlerin sadece kağıda yazılmış bilgiler olduğunu sanıyor. Genler aslında neyin üzerine yazılıdır?","steps":[{"t":"Genin gerçek yapısı","a":"Bir madde","d":"Genler kağıda yazılı yazılar değildir, gerçek bir maddeden oluşur. Bu madde hücrenin çekirdeğinde bulunur."},{"t":"Genin maddesi","a":"DNA","d":"Genler, DNA adı verilen molekülün parçalarıdır. Yani genetik bilgi DNA üzerine yazılıdır."}],"ans":"Genler DNA molekülü üzerine yazılıdır"},{"q":"Bir çocuğun hem annesine hem babasına benzemesinin nedeni genlerle nasıl açıklanır?","steps":[{"t":"Genlerin gelişi","a":"İki kaynaktan","d":"Çocuğun genlerinin yarısı anneden, yarısı babadan gelir. Genler özelliklerimizi belirler."},{"t":"Benzeme nedeni","a":"Karışık genler","d":"Anneden ve babadan gelen genler birlikte özellikleri oluşturur. Bu yüzden çocuk hem annesine hem babasına benzeyebilir."}],"ans":"Genlerinin yarısı anneden yarısı babadan geldiği için her ikisine de benzer"},{"q":"Bir hayvanın tüy rengi geni ile aynı hayvanın gözlerinin görme görevi farklı genlerce yönetilir. Bu durum genler hakkında bize neyi gösterir?","steps":[{"t":"Farklı özellikler","a":"Farklı genler","d":"Tüy rengi ve görme gibi farklı özellikler farklı genler tarafından yönetilir. Her özelliğin kendi geni vardır."},{"t":"Sonuç","a":"Çok sayıda gen","d":"Bu durum, bir canlıda çok sayıda gen bulunduğunu gösterir. Her gen ayrı bir özelliği belirlemekle görevlidir."}],"ans":"Her özelliğin ayrı bir geni olduğunu, canlıda çok sayıda gen bulunduğunu gösterir"}]},"ortaokul":{"kolay":[{"q":"Gen, bir özelliği belirlerken aslında neyin üretimini şifreler?","steps":[{"t":"Genin görevi","a":"Şifre verir","d":"Gen, DNA üzerinde anlamlı bir bölümdür ve bir bilgi taşır. Bu bilgi hücreye bir madde üretmesini söyler."},{"t":"Üretilen madde","a":"Protein","d":"Genler protein üretimini şifreler. Üretilen proteinler de canlının özelliklerini ortaya çıkarır."}],"ans":"Protein üretimini şifreler"},{"q":"Bir canlının dış görünüşüne (örneğin uzun boylu olması) ne ad verilir?","steps":[{"t":"Görünen özellik","a":"Dış görünüş","d":"Bir canlının dışarıdan gözlenebilen özellikleri vardır. Boy, renk, şekil gibi özellikler buna örnektir."},{"t":"Terim","a":"Fenotip","d":"Canlının gözle görülen dış özelliklerine fenotip denir. Uzun boylu olmak bir fenotip örneğidir."}],"ans":"Fenotip"},{"q":"Bir canlının genlerinin tümüne, yani genetik yapısına ne ad verilir?","steps":[{"t":"Genlerin tümü","a":"Gen yapısı","d":"Bir canlının taşıdığı bütün genler bir araya gelerek genetik yapısını oluşturur. Bu yapı dışarıdan görülmez."},{"t":"Terim","a":"Genotip","d":"Canlının sahip olduğu genlerin tümüne genotip denir. Genotip, fenotipi belirleyen kalıtsal yapıdır."}],"ans":"Genotip"},{"q":"DNA dan proteine giden bilgi akışı sırasında DNA ile protein arasında görev yapan molekül hangisidir?","steps":[{"t":"Bilgi akışı","a":"DNA dan proteine","d":"Genetik bilgi DNA da saklıdır, ancak protein doğrudan DNA dan yapılmaz. Aracı bir moleküle ihtiyaç vardır."},{"t":"Aracı molekül","a":"RNA","d":"DNA daki bilgi önce RNA ya aktarılır, sonra RNA proteinin yapımını sağlar. Yani DNA ile protein arasında RNA görev yapar."}],"ans":"RNA"},{"q":"Genetik şifrede üç nükleotitten oluşan ve bir aminoasiti belirten birime ne ad verilir?","steps":[{"t":"Şifrenin birimi","a":"Üçlü grup","d":"Genetik şifre, nükleotitlerin üçlü gruplar halinde okunmasıyla anlam kazanır. Her üçlü grup bir bilgi taşır."},{"t":"Terim","a":"Kodon","d":"Üç nükleotitten oluşan bu birime kodon denir. Her kodon, proteinin yapı taşı olan bir aminoasiti belirtir."}],"ans":"Kodon"}],"zor":[{"q":"Proteinler aminoasitlerden oluşur. Genin nükleotit dizisi ile proteinin aminoasit dizisi arasındaki ilişkiyi kodon kavramıyla açıklayınız.","steps":[{"t":"Genin yapısı","a":"Nükleotit dizisi","d":"Gen, belirli bir sırada dizilmiş nükleotitlerden oluşur. Bu sıralama bir şifre içerir."},{"t":"Kodon-aminoasit","a":"Üçlü okuma","d":"Nükleotitler üçerli gruplar halinde okunur ve her üçlüye kodon denir. Her kodon belirli bir aminoasiti belirtir."},{"t":"Sonuç","a":"Dizi belirler","d":"Kodonların sırası, proteindeki aminoasitlerin sırasını belirler. Böylece gen, proteinin yapısını şifrelemiş olur."}],"ans":"Gendeki nükleotitler üçlü kodonlar halinde okunur, her kodon bir aminoasiti belirleyerek proteinin dizisini oluşturur"},{"q":"Aynı genetik kod, bir bakteride de insanda da aynı aminoasidi şifreler. Bu duruma ne ad verilir ve bize ne anlatır?","steps":[{"t":"Ortak kod","a":"Aynı şifre","d":"İncelenen hemen hemen tüm canlılarda belirli bir kodon aynı aminoasidi şifreler. Yani genetik kod canlılar arasında ortaktır."},{"t":"Terim","a":"Evrensellik","d":"Genetik kodun bütün canlılarda aynı olmasına genetik kodun evrenselliği denir. Bakteriden insana kadar geçerlidir."},{"t":"Anlamı","a":"Ortak köken","d":"Bu evrensellik, canlıların ortak bir kökenden gelmiş olabileceğine işaret eder. Ayrıca bir canlının geninin başka canlıda da çalışabilmesini sağlar."}],"ans":"Genetik kodun evrenselliği; canlıların ortak kökenli olabileceğini ve genlerin türler arası çalışabileceğini gösterir"},{"q":"Bir aminoasiti birden fazla kodonun şifreleyebildiği bilinmektedir. Bu özelliğe ne ad verilir ve canlı için olası faydası nedir?","steps":[{"t":"Çok kodon","a":"Tekrar","d":"Bazı aminoasitler tek bir kodonla değil, birden çok kodonla şifrelenebilir. Yani farklı üçlüler aynı aminoasidi belirtebilir."},{"t":"Terim","a":"Dejenere kod","d":"Genetik kodun bu özelliğine kodun dejenere (yedekli) olması denir. 64 kodon, 20 aminoasidi şifrelediği için bazı aminoasitlerin birden çok kodonu vardır."},{"t":"Faydası","a":"Hata toleransı","d":"Bu özellik sayesinde bir nükleotitteki bazı değişiklikler aminoasidi değiştirmeyebilir. Böylece mutasyonların zararlı etkisi kısmen azalır."}],"ans":"Genetik kodun dejenere (yedekli) olması; bazı mutasyonların aminoasidi değiştirmemesini sağlayarak zararı azaltır"},{"q":"Santral dogma olarak bilinen bilgi akışını sırasıyla yazınız ve her aşamada hangi olayın gerçekleştiğini belirtiniz.","steps":[{"t":"Birinci aşama","a":"DNA dan RNA ya","d":"DNA daki bilgi önce RNA ya aktarılır, bu olaya transkripsiyon (yazılma) denir. RNA, DNA nın ilgili bölümünün kopyasını taşır."},{"t":"İkinci aşama","a":"RNA dan proteine","d":"RNA daki kodonlar okunarak proteinin aminoasit dizisi oluşturulur, bu olaya translasyon (çevrilme) denir. Böylece protein sentezlenir."},{"t":"Genel akış","a":"DNA → RNA → protein","d":"Bilgi akışı DNA dan RNA ya, oradan da proteine doğrudur. Bu temel akışa santral dogma denir."}],"ans":"DNA → RNA → protein; DNA dan RNA ya transkripsiyon, RNA dan proteine translasyon ile geçilir"},{"q":"Genotip ve fenotip arasındaki ilişkiyi bir örnekle açıklayınız ve fenotipin sadece genotipe mi bağlı olduğunu tartışınız.","steps":[{"t":"Genotip","a":"Gen yapısı","d":"Genotip, bir canlının taşıdığı genlerin tümüdür. Örneğin bir bitkinin uzun boy genlerini taşıması genotiptir."},{"t":"Fenotip","a":"Dış görünüş","d":"Fenotip, genotipin dışa yansıyan görünümüdür. Bitkinin gerçekten uzun boylu olması fenotiptir."},{"t":"Çevre etkisi","a":"Sadece gen değil","d":"Fenotip yalnızca genotipe bağlı değildir, çevre koşulları da etkiler. Örneğin yeterli su ve ışık almayan bitki, uzun boy geni taşısa bile kısa kalabilir."}],"ans":"Genotip genlerin tümü, fenotip dış görünüştür; fenotip hem genotipe hem çevre koşullarına bağlıdır"}]},"lise":{"kolay":[{"q":"Genetik kodda mRNA üzerindeki üç nükleotitlik birime kodon denir. Toplam kaç farklı kodon vardır ve bunlar kaç çeşit aminoasidi şifreler?","steps":[{"t":"Kodon sayısı","a":"4 üzeri 3","d":"RNA da dört farklı nükleotit bulunur ve kodon üç nükleotitten oluşur. Olası kombinasyon sayısı 4 × 4 × 4 = 64 tür."},{"t":"Aminoasit sayısı","a":"20 çeşit","d":"Bu 64 kodon, proteinleri oluşturan 20 çeşit aminoasidi şifreler. 64 ten fazla kodon olduğu için bazı aminoasitlerin birden çok kodonu vardır."}],"ans":"64 kodon, 20 çeşit aminoasidi şifreler"},{"q":"Protein sentezinin başlamasını sağlayan ve genellikle metiyonin aminoasidini şifreleyen başlatma kodonu hangisidir?","steps":[{"t":"Başlatma sinyali","a":"Özel kodon","d":"Protein sentezi rastgele bir yerden başlamaz, belirli bir kodonla başlar. Bu kodon ribozoma nereden okumaya başlayacağını bildirir."},{"t":"Başlatma kodonu","a":"AUG","d":"Başlatma kodonu AUG dur ve metiyonin aminoasidini şifreler. Translasyon bu kodonla başlar."}],"ans":"AUG (metiyonin)"},{"q":"Translasyonu sonlandıran ve herhangi bir aminoasidi şifrelemeyen kodonlara ne ad verilir?","steps":[{"t":"Sonlandırma ihtiyacı","a":"Dur sinyali","d":"Protein sentezinin belirli bir noktada durması gerekir. Bunu sağlayan özel kodonlar vardır."},{"t":"Sonlandırma kodonları","a":"Stop kodonları","d":"UAA, UAG ve UGA kodonları aminoasit şifrelemez ve sentezi durdurur. Bunlara durdurma (stop) kodonları denir."}],"ans":"Durdurma (stop) kodonları (UAA, UAG, UGA)"},{"q":"Genetik kodun evrensel olması ne anlama gelir?","steps":[{"t":"Ortak kod","a":"Tüm canlılarda","d":"Bir kodonun belirttiği aminoasit, neredeyse tüm canlılarda aynıdır. Bakteri, bitki ve insanda aynı kodon aynı aminoasidi şifreler."},{"t":"Evrensellik","a":"Ortak köken","d":"Bu ortaklığa genetik kodun evrenselliği denir. Bu durum, canlıların ortak bir atadan geldiğine kanıt olarak gösterilir."}],"ans":"Genetik kodun hemen tüm canlılarda aynı kodon-aminoasit karşılığını taşımasıdır"},{"q":"Genetik kodun dejenere (yedekli) olması ne demektir?","steps":[{"t":"Kodon fazlalığı","a":"64 e karşı 20","d":"64 kodon vardır ama yalnızca 20 aminoasit şifrelenir. Bu fazlalık bir özellik doğurur."},{"t":"Dejenere kod","a":"Çok kodon bir aminoasit","d":"Bir aminoasidin birden fazla kodon tarafından şifrelenmesine kodun dejenere olması denir. Örneğin lösin aminoasidi birden çok kodonla şifrelenebilir."}],"ans":"Bir aminoasidin birden fazla kodon tarafından şifrelenebilmesidir"},{"q":"Santral dogmaya göre genetik bilgi hangi sırayla akar?","steps":[{"t":"Bilginin kaynağı","a":"DNA","d":"Genetik bilgi DNA da saklıdır. Bu bilgi doğrudan proteine değil, önce bir ara moleküle aktarılır."},{"t":"Akış sırası","a":"DNA → RNA → protein","d":"DNA daki bilgi transkripsiyonla RNA ya, RNA daki bilgi translasyonla proteine aktarılır. Bu temel akışa santral dogma denir."}],"ans":"DNA → RNA → Protein"},{"q":"Transkripsiyon ve translasyon kavramları sırasıyla hangi olayları ifade eder?","steps":[{"t":"Transkripsiyon","a":"DNA dan RNA","d":"Transkripsiyon, DNA daki bilginin RNA ya kopyalanması olayıdır. Türkçesi yazılmadır."},{"t":"Translasyon","a":"RNA dan protein","d":"Translasyon, RNA daki kodonların okunarak proteinin sentezlenmesi olayıdır. Türkçesi çevrilmedir."}],"ans":"Transkripsiyon DNA dan RNA sentezi, translasyon RNA dan protein sentezidir"},{"q":"Bir genin taşıdığı bilgi neyi belirler ve bu bilgi proteinin hangi özelliğini ortaya çıkarır?","steps":[{"t":"Genin bilgisi","a":"Nükleotit dizisi","d":"Bir gen, belirli bir nükleotit dizisi taşır. Bu dizi proteinin yapımı için şifre içerir."},{"t":"Belirlenen özellik","a":"Aminoasit dizisi","d":"Gendeki nükleotit dizisi, proteindeki aminoasitlerin sırasını belirler. Aminoasit dizisi de proteinin yapısını ve görevini belirler."}],"ans":"Gen, proteinin aminoasit dizisini belirler; bu dizi proteinin yapı ve işlevini ortaya çıkarır"},{"q":"Genotip ve fenotip terimleri sırasıyla neyi ifade eder?","steps":[{"t":"Genotip","a":"Genetik yapı","d":"Genotip, bir bireyin sahip olduğu genlerin tümünü ifade eder. Doğrudan gözlenemez, kalıtsal yapıdır."},{"t":"Fenotip","a":"Dış görünüş","d":"Fenotip, genotipin çevreyle birlikte ortaya çıkardığı gözlenebilir özelliklerdir. Boy, renk gibi özellikler fenotiptir."}],"ans":"Genotip bireyin genetik yapısı, fenotip ise gözlenebilen dış özellikleridir"},{"q":"Bir mRNA üzerinde 30 nükleotit varsa ve hepsi kodlama yapıyorsa, bu mRNA dan kaç aminoasitlik bir protein parçası oluşur?","steps":[{"t":"Kodon başına nükleotit","a":"3 er","d":"Her kodon üç nükleotitten oluşur ve bir aminoasidi şifreler. Aminoasit sayısını bulmak için nükleotit sayısını üçe böleriz."},{"t":"Hesap","a":"30 ÷ 3","d":"30 nükleotit üçe bölünürse 10 kodon elde edilir. Her kodon bir aminoasit şifrelediği için 10 aminoasit oluşur."}],"ans":"10 aminoasit"},{"q":"mRNA, tRNA ve rRNA gibi RNA çeşitleri vardır. Bunlardan kodonları aminoasitle eşleştirmek için antikodon taşıyan RNA hangisidir?","steps":[{"t":"RNA çeşitleri","a":"Farklı görevler","d":"Protein sentezinde farklı RNA çeşitleri görev alır. Her birinin özel bir işlevi vardır."},{"t":"Antikodon taşıyan","a":"tRNA","d":"tRNA, bir ucunda antikodon, diğer ucunda aminoasit taşır. Antikodonu mRNA daki kodonla eşleşerek doğru aminoasidi getirir."}],"ans":"tRNA (taşıyıcı RNA)"},{"q":"mRNA üzerindeki kodona karşılık gelen ve tRNA üzerinde bulunan üçlü nükleotit dizisine ne ad verilir?","steps":[{"t":"Eşleşme ihtiyacı","a":"Kodon-tRNA","d":"Translasyonda her kodonun doğru aminoasitle eşleşmesi gerekir. Bu eşleşmeyi tRNA sağlar."},{"t":"Üçlü dizi","a":"Antikodon","d":"tRNA üzerinde, mRNA kodonuna tamamlayıcı olan üçlü nükleotit dizisine antikodon denir. Antikodon kodonla baz eşleşmesi yapar."}],"ans":"Antikodon"},{"q":"Translasyon olayının gerçekleştiği, kodonların okunup aminoasitlerin birleştirildiği hücre yapısı hangisidir?","steps":[{"t":"Protein sentez yeri","a":"Bir organel","d":"Protein sentezi belirli bir hücre yapısında gerçekleşir. Bu yapı mRNA yı okur ve proteini birleştirir."},{"t":"Yapı","a":"Ribozom","d":"Translasyon ribozomlarda gerçekleşir. Ribozom mRNA daki kodonları okuyarak aminoasitleri peptit bağıyla birleştirir."}],"ans":"Ribozom"},{"q":"DNA daki bilginin RNA ya aktarılması sırasında DNA daki timin (T) bazının karşısına RNA da hangi baz gelir?","steps":[{"t":"RNA bazları","a":"Timin yok","d":"RNA da DNA dakinden farklı olarak timin bazı bulunmaz. Onun yerine başka bir baz kullanılır."},{"t":"Karşılık gelen baz","a":"Adenin → urasil","d":"Transkripsiyonda DNA daki timinin (yani adeninin eşi) karşısına RNA da urasil gelir. RNA da timin yerine urasil bazı vardır."}],"ans":"Urasil (U)"},{"q":"Genotip ile fenotip arasındaki ilişkide çevrenin rolü nedir? Tek yumurta ikizleri örneğiyle açıklayınız.","steps":[{"t":"İkizlerin genotipi","a":"Aynı","d":"Tek yumurta ikizleri aynı genotipe, yani aynı genlere sahiptir. Bu yüzden birçok özellikleri benzerdir."},{"t":"Fenotip farkı","a":"Çevre etkisi","d":"Buna rağmen farklı beslenme, spor veya yaşam koşulları ikizlerin fenotiplerini farklılaştırabilir. Örneğin biri daha kaslı olabilir."}],"ans":"Aynı genotipteki ikizler farklı çevre koşullarında farklı fenotip gösterebilir; çevre fenotipi etkiler"}],"zor":[{"q":"Bir gende tek bir nükleotit değişmesine rağmen üretilen proteinde aminoasit değişmeyebilir. Bu durumu genetik kodun dejenere olması ile açıklayınız.","steps":[{"t":"Dejenere kod","a":"Yedekli kodon","d":"Bir aminoasit birden fazla kodon tarafından şifrelenebilir, buna kodun dejenere olması denir. Genellikle kodonun üçüncü nükleotiti değişse de aminoasit aynı kalabilir."},{"t":"Sessiz mutasyon","a":"Aminoasit aynı","d":"Nükleotit değişimi yeni kodonu yine aynı aminoasidi şifreleyen başka bir kodona çevirebilir. Bu durumda protein değişmez, buna sessiz mutasyon denir."},{"t":"Sonuç","a":"Etki yok","d":"Bu nedenle bazı nükleotit değişiklikleri proteinin yapısını ve işlevini etkilemez. Genetik kodun yedekliliği bu koruyucu etkiyi sağlar."}],"ans":"Dejenere kod sayesinde değişen kodon aynı aminoasidi şifreleyebilir (sessiz mutasyon), bu yüzden protein değişmez"},{"q":"Orak hücreli anemi, bir gendeki tek nükleotit değişiminin sonucudur. Bu mutasyonun santral dogma boyunca nasıl bir etkiye yol açtığını sırasıyla açıklayınız.","steps":[{"t":"DNA değişimi","a":"Tek nükleotit","d":"Hemoglobin geninde tek bir nükleotit değişir. Bu değişim, ilgili kodonu farklı bir kodona dönüştürür."},{"t":"RNA ve aminoasit","a":"Yanlış aminoasit","d":"Değişen kodon translasyonda farklı bir aminoasidin yerleştirilmesine neden olur. Hemoglobinde bir aminoasit yanlış olarak değişir."},{"t":"Protein etkisi","a":"Yapı bozulur","d":"Tek aminoasit değişimi hemoglobinin yapısını ve şeklini değiştirir. Bu, alyuvarların orak şekline girmesine yol açar."},{"t":"Fenotip","a":"Hastalık","d":"Orak şekilli alyuvarlar oksijen taşımada yetersiz kalır ve damarları tıkayabilir. Sonuçta orak hücreli anemi hastalığı ortaya çıkar."}],"ans":"DNA daki tek nükleotit değişimi yanlış aminoasit eklenmesine, bu da bozuk hemoglobine ve orak şekilli alyuvarlara yol açar"},{"q":"Genetik kodun evrensel olması, biyoteknolojide insan insülin geninin bakteriye aktarılıp insülin üretilmesini mümkün kılar. Bu uygulamanın bilimsel temelini açıklayınız.","steps":[{"t":"Evrensel kod","a":"Ortak şifre","d":"Genetik kod hemen tüm canlılarda aynıdır, yani bir kodon her canlıda aynı aminoasidi şifreler. Bu yüzden farklı türlerin genleri birbirinde okunabilir."},{"t":"Gen aktarımı","a":"İnsan geni bakteriye","d":"İnsan insülin geni bir bakteriye aktarılır. Bakteri bu geni kendi geni gibi okuyabilir çünkü kod ortaktır."},{"t":"Üretim","a":"Bakteri insülin yapar","d":"Bakteri, insan insülin genini transkripsiyon ve translasyonla işleyerek insan insülini üretir. Böylece ilaç olarak insülin büyük miktarda elde edilir."}],"ans":"Genetik kod evrensel olduğundan bakteri, kendisine aktarılan insan insülin genini doğru okuyup insan insülini üretebilir"},{"q":"Çerçeve kayması (frameshift) mutasyonu, bir nükleotitin eklenmesi veya çıkarılmasıyla oluşur. Bu mutasyonun neden tek nükleotit değişiminden (nokta mutasyonu) daha ciddi sonuçlar doğurduğunu açıklayınız.","steps":[{"t":"Okuma çerçevesi","a":"Üçerli okuma","d":"mRNA kodonları başlangıçtan itibaren üçer üçer okunur, buna okuma çerçevesi denir. Doğru okuma için bu çerçevenin korunması gerekir."},{"t":"Nükleotit ekleme/çıkarma","a":"Çerçeve kayar","d":"Bir nükleotit eklenir veya çıkarılırsa, o noktadan sonraki tüm kodonlar kayar ve farklı okunur. Bu yüzden değişimden sonraki bütün aminoasitler yanlış olur."},{"t":"Nokta mutasyonu farkı","a":"Sadece bir kodon","d":"Nokta mutasyonunda yalnızca tek bir kodon etkilenir ve çoğu zaman tek bir aminoasit değişir. Çerçeve kaymasında ise proteinin büyük kısmı bozulur."},{"t":"Sonuç","a":"Daha ciddi","d":"Bu nedenle çerçeve kayması mutasyonu genellikle işlevsiz protein üretir ve daha ciddi etkiler doğurur. Hatta erken bir durdurma kodonu oluşturup proteini kısaltabilir."}],"ans":"Çerçeve kayması okuma çerçevesini bozarak değişimden sonraki tüm kodonları yanlış okutur, bu yüzden nokta mutasyonundan çok daha ciddi sonuç verir"},{"q":"Bir mRNA dizisi 5'-AUG-GCU-UUU-UAA-3' şeklindedir. Bu mRNA dan kaç aminoasitlik bir protein sentezlenir? Sebebiyle açıklayınız.","steps":[{"t":"Kodonlara ayır","a":"Dört kodon","d":"mRNA üçerli kodonlara ayrılır: AUG, GCU, UUU, UAA. Toplam dört kodon bulunur."},{"t":"Kodonların görevi","a":"AUG başlat, UAA dur","d":"AUG başlatma kodonudur ve metiyonini şifreler, ayrıca proteine dahil olur. UAA ise durdurma kodonudur ve aminoasit şifrelemez."},{"t":"Aminoasit sayımı","a":"3 aminoasit","d":"AUG, GCU ve UUU birer aminoasit kodlar, UAA ise proteine aminoasit eklemez. Bu yüzden proteinde 3 aminoasit bulunur."}],"ans":"3 aminoasit; çünkü AUG, GCU ve UUU birer aminoasit kodlar, UAA durdurma kodonu olup aminoasit eklemez"},{"q":"Tüm vücut hücreleri aynı genleri (aynı genotipi) taşıdığı halde sinir hücresi ile kas hücresi farklı yapı ve işleve sahiptir. Bu durumu gen ifadesi ile açıklayınız.","steps":[{"t":"Aynı genotip","a":"Ortak DNA","d":"Bir bireyin tüm vücut hücreleri mitozla oluştuğu için aynı DNA yı, dolayısıyla aynı genleri taşır. Yani genotipleri aynıdır."},{"t":"Seçici ifade","a":"Farklı genler aktif","d":"Her hücre tipinde genlerin yalnızca bir kısmı aktif olarak ifade edilir, diğerleri kapalıdır. Sinir hücresinde farklı genler, kas hücresinde farklı genler çalışır."},{"t":"Sonuç","a":"Farklı proteinler","d":"Farklı genlerin ifade edilmesi farklı proteinlerin üretilmesine yol açar. Bu farklı proteinler hücrelere farklı yapı ve işlev kazandırır."}],"ans":"Aynı genotipteki hücreler farklı genleri ifade ettiğinden farklı proteinler üretir, bu da farklı yapı ve işlev sağlar"},{"q":"DNA daki bir gen bölgesinin anlamlı (kodlayan) zinciri 3'-TAC-3' ile başlıyorsa, bundan sentezlenen mRNA nın başlangıç kodonu ne olur ve bu hangi olayı başlatır?","steps":[{"t":"Kalıp zincir","a":"TAC","d":"Transkripsiyonda RNA, DNA kalıp zincirine tamamlayıcı olarak sentezlenir. Kalıp 3'-TAC-5' ise RNA bu zincire göre okunur."},{"t":"mRNA kodonu","a":"AUG","d":"TAC kalıbına karşılık RNA da A-U-G bazları gelir (T karşısına A, A karşısına U, C karşısına G). Böylece mRNA AUG kodonuyla başlar."},{"t":"Başlattığı olay","a":"Translasyon başlar","d":"AUG başlatma kodonudur ve metiyonini şifreler. Bu kodon translasyonun, yani protein sentezinin başlamasını sağlar."}],"ans":"mRNA başlangıç kodonu AUG olur; AUG başlatma kodonu olarak translasyonu (protein sentezini) başlatır"},{"q":"Genetik kod dejenere olduğu halde belirsiz (çift anlamlı) değildir. Bu iki kavramın farkını açıklayınız ve bunun protein sentezi için önemini belirtiniz.","steps":[{"t":"Dejenere olma","a":"Çok kodon → 1 aminoasit","d":"Dejenerelik, bir aminoasidin birden çok kodonla şifrelenebilmesidir. Yani birden fazla farklı kodon aynı aminoasidi belirtebilir."},{"t":"Belirsiz olmama","a":"1 kodon → 1 aminoasit","d":"Belirsiz olmama, bir kodonun her zaman yalnızca tek bir aminoasidi şifrelemesi demektir. Bir kodon asla iki farklı aminoasit anlamına gelmez."},{"t":"Önemi","a":"Doğru sentez","d":"Bu sayede ribozom her kodonu okuduğunda hangi aminoasidi ekleyeceğinden emindir. Belirsizlik olmaması, proteinlerin her seferinde doğru ve aynı şekilde sentezlenmesini garanti eder."}],"ans":"Dejenere bir aminoasidin çok kodonu olmasıdır; belirsiz olmama ise her kodonun tek aminoasit şifrelemesidir; bu doğru protein sentezini garanti eder"},{"q":"Bir bilim insanı, bir proteinin 100 aminoasitten oluştuğunu belirliyor. Bu proteini kodlayan mRNA nın kodlama bölgesinde durdurma kodonu dahil en az kaç nükleotit bulunması gerektiğini hesaplayınız.","steps":[{"t":"Aminoasit kodonları","a":"100 kodon","d":"100 aminoasitin her biri bir kodonla şifrelenir, bu da 100 kodon eder. Başlatma kodonu da bir aminoasit (metiyonin) şifrelediği için bu 100 e dahildir."},{"t":"Durdurma kodonu","a":"+1 kodon","d":"Sentezin bitmesi için ek olarak bir durdurma kodonu gerekir, bu kodon aminoasit eklemez. Böylece toplam kodon sayısı 100 + 1 = 101 olur."},{"t":"Nükleotit hesabı","a":"101 × 3","d":"Her kodon üç nükleotitten oluşur, bu yüzden nükleotit sayısı 101 × 3 = 303 tür. Yani kodlama bölgesinde en az 303 nükleotit bulunmalıdır."}],"ans":"303 nükleotit (100 aminoasit kodonu + 1 durdurma kodonu = 101 kodon × 3)"},{"q":"Mutasyon sonucu bir gende durdurma kodonu, normalden erken oluşursa proteine ne olur? Bu mutasyonun olası sonucunu açıklayınız.","steps":[{"t":"Erken durdurma","a":"Vaktinden önce","d":"Mutasyon, normalde aminoasit kodlayan bir kodonu durdurma kodonuna çevirebilir. Bu durdurma kodonu proteinin ortasında erken ortaya çıkar."},{"t":"Sentez kesilir","a":"Kısa protein","d":"Translasyon erken durdurma kodonunda sona erer ve protein tamamlanamaz. Böylece normalden daha kısa, eksik bir protein oluşur."},{"t":"İşlev kaybı","a":"Bozuk protein","d":"Eksik protein genellikle doğru katlanamaz ve işlevini yerine getiremez. Bu durum, ilgili özelliğin kaybına veya kalıtsal hastalığa yol açabilir."}],"ans":"Erken durdurma kodonu translasyonu zamanından önce bitirir, kısa ve işlevsiz bir protein oluşur, bu da işlev kaybına yol açabilir"},{"q":"Genin nükleotit dizisi ile fenotip arasındaki bağlantıyı, gen-protein-özellik ilişkisi üzerinden adım adım açıklayınız.","steps":[{"t":"Gen ve dizi","a":"Nükleotit sırası","d":"Gen, belirli bir sırada dizilmiş nükleotitlerden oluşur. Bu sıralama, üretilecek proteinin şifresini içerir."},{"t":"Protein sentezi","a":"Transkripsiyon-translasyon","d":"Gendeki bilgi önce mRNA ya aktarılır, sonra ribozomda proteine çevrilir. Nükleotit dizisi, proteinin aminoasit dizisini belirler."},{"t":"Protein işlevi","a":"Enzim/yapı","d":"Oluşan protein, enzim veya yapı maddesi olarak hücrede bir görev üstlenir. Örneğin bir pigment proteini renk oluşturur."},{"t":"Fenotip","a":"Görünür özellik","d":"Proteinin işlevi gözlenebilir bir özellik olarak ortaya çıkar, buna fenotip denir. Böylece gendeki dizi sonuçta canlının görünen özelliğini belirler."}],"ans":"Gendeki nükleotit dizisi proteinin aminoasit dizisini, protein de işleviyle fenotipi belirler (gen → protein → özellik)"},{"q":"mRNA üzerindeki kodon 5'-GCA-3' ise bu kodonu okuyan tRNA nın antikodonu nasıl olmalıdır? Baz eşleşmesi ile açıklayınız.","steps":[{"t":"Kodon-antikodon","a":"Tamamlayıcı","d":"tRNA nın antikodonu, mRNA kodonuyla tamamlayıcı baz eşleşmesi yapar. Yani karşılıklı bazlar birbirini tutar."},{"t":"Baz eşleşmesi","a":"G-C, C-G, A-U","d":"RNA da A urasil ile, G ise sitozin ile eşleşir. GCA kodonunda G karşısına C, C karşısına G, A karşısına U gelir."},{"t":"Antikodon yönü","a":"3'-CGU-5'","d":"Antikodon kodona ters yönde (antiparalel) eşleştiği için 3'-CGU-5' şeklinde yazılır. Böylece tRNA doğru aminoasidi kodona getirir."}],"ans":"Antikodon CGU dur (3'-CGU-5'); G-C, C-G ve A-U baz eşleşmesiyle kodonla tamamlayıcı şekilde bağlanır"},{"q":"Bir öğrenci DNA daki tüm bölgelerin protein şifrelediğini sanıyor. Genlerin yapısı ve düzenleyici/kodlamayan bölgeler dikkate alındığında bu yanılgıyı düzeltiniz.","steps":[{"t":"Yanılgı","a":"Her yer kod değil","d":"DNA nın tamamı protein şifrelemez, sadece belirli bölümler bunu yapar. Geri kalan büyük kısım protein kodlamayan bölgelerden oluşur."},{"t":"Kodlamayan bölgeler","a":"Düzenleyici/ara diziler","d":"DNA da gen ifadesini düzenleyen bölgeler, genler arası bölgeler ve gen içindeki kodlamayan ara diziler bulunur. Bu bölgeler protein şifrelemez ama önemli görevler üstlenir."},{"t":"Düzeltme","a":"Sadece genler","d":"Yalnızca genlerin kodlayan bölümleri protein şifresi taşır. Dolayısıyla DNA nın tümü değil, belirli kısımları protein kodlar; öğrencinin düşüncesi yanlıştır."}],"ans":"DNA nın tümü değil, yalnızca genlerin kodlayan bölgeleri protein şifreler; düzenleyici ve kodlamayan bölgeler protein kodlamaz"},{"q":"Aynı türün iki bireyinin genotipleri farklı olduğu halde aynı fenotipi gösterebilir. Bu durumu baskın ve çekinik gen kavramlarıyla açıklayınız.","steps":[{"t":"Genotip seçenekleri","a":"Saf ve melez","d":"Bir özellik için birey iki baskın gen (saf baskın) ya da bir baskın bir çekinik gen (melez) taşıyabilir. Bu iki genotip farklıdır."},{"t":"Baskınlık","a":"Baskın gizler çekiniği","d":"Baskın gen, yanındaki çekinik genin etkisini gizler ve fenotipte kendini gösterir. Melez bireyde sadece baskın özellik görünür."},{"t":"Sonuç","a":"Aynı fenotip","d":"Saf baskın (örneğin AA) ve melez (Aa) bireylerin genotipleri farklıdır ama her ikisinde de baskın özellik görünür. Bu yüzden farklı genotipler aynı fenotipi verebilir."}],"ans":"Saf baskın ve melez genotipler farklıdır ama baskın gen çekiniği gizlediğinden her ikisi de aynı (baskın) fenotipi gösterir"},{"q":"Genetik kodun evrensel ve dejenere olmasının canlılar için sağladığı iki ayrı avantajı karşılaştırmalı olarak açıklayınız.","steps":[{"t":"Evrensellik avantajı","a":"Gen aktarımı","d":"Genetik kod tüm canlılarda aynı olduğu için bir türün geni başka bir türde de doğru okunabilir. Bu, biyoteknolojide gen aktarımını ve canlıların ortak kökeninin anlaşılmasını sağlar."},{"t":"Dejenerelik avantajı","a":"Mutasyon koruması","d":"Bir aminoasidin birden çok kodonu olması, bazı nükleotit değişimlerinin aminoasidi değiştirmemesini sağlar. Böylece dejenerelik mutasyonların zararlı etkisine karşı koruma sunar."},{"t":"Karşılaştırma","a":"Ortaklık ve dayanıklılık","d":"Evrensellik canlılar arası ortaklık ve uygulama imkânı sağlarken, dejenerelik genetik bilgiyi mutasyonlara karşı dayanıklı kılar. İkisi de kodun güvenilirliğini ve esnekliğini artırır."}],"ans":"Evrensellik genlerin türler arası okunmasını (gen aktarımı, ortak köken) sağlar; dejenerelik ise mutasyonlara karşı koruma sağlayarak genetik bilgiyi dayanıklı kılar"}]}}};
